content:
显然只会存在 $3$ 种本质不同的方式选择两个矩形。

1. 两个矩形不相交。

这种情况可以直接遍历所有平行 $x/y$ 轴的分割线，使选取的两个矩形分别在分割线的两边。分别找出极值点直接计算即可。


2. 相交成一个十字。

可以发现此时两个矩形都至少有两条边在恰好包含所有点的大矩形的边界上。

因此，为了有效找出这样的矩形，考虑遍历“竖”矩形的右边界。令 $L_d$ 为“竖”矩形左边界左侧点最小 $y$ 坐标，$L_u$ 为左边界左侧点最大 $y$ 坐标，同理定义右边界右侧点的 $R_u,R_d$。

假设 $R_u\ge L_u$。在 $L_d\ge R_d$ 的前缀上，直接选择最右的边界。而在剩下的子区间将会满足 $L_u\le R_u,L_d\le R_d$。假设矩形固定的边界为 $L,R$，则总面积为 $(R_u-L_d)\cdot H+(R-L)\cdot W$，其中 $H$ 表示大矩形的长度，$W$ 表示大矩形的高度。改一下就可以得到：$(R\cdot W+R_u\cdot H)-(L\cdot W+L_d\cdot H)$,线段树维护一下区间最值即可。


3. 两个矩形各自有一个顶点在另一个矩形内部。

可以发现此时这两个矩形一定各有一个角与大矩形的某个角重合，即这两个分别覆盖对角，总共只有覆盖左上角和右下角以及覆盖左下角覆盖右上角两种情况。

假设是覆盖左上和右下。考虑遍历 $x$ 轴，求出前缀 $y$ 的最小值和后缀最大值。然后直接暴力枚举点对就是 $\mathcal O (n^2) $ 的，考虑优化。可以发现由于要满足两个矩形相交，因此对于每个左上矩形右下角点，所对应右下矩形左上角点的就是一段区间，维护区间静态凸包即可。

```cpp
#include<bits/stdc++.h>
#define R(i,a,b) for(int i=(a),i##E=(b);i<=i##E;i++)
#define L(i,a,b) for(int i=(b),i##E=(a);i>=i##E;i--)
using namespace std;
const int N=222222;

int n;
long long ans,v[N];
pair<int,int>p[N];
void calc1()
{
	sort(p+1,p+n+1);
	R(i,0,n+5) v[i]=0;
	int mny=p[1].second,mxy=p[1].second;
	R(i,2,n) 
	{
		mny=min(mny,p[i].second);
		mxy=max(mxy,p[i].second);
		v[i]=1ll*(p[i].first-p[1].first)*(mxy-mny);
	}
	mny=p[n].second,mxy=p[n].second;
	L(i,1,n-1) 
	{
		mny=min(mny,p[i].second);
		mxy=max(mxy,p[i].second);
		v[i-1]+=1ll*(p[n].first-p[i].first)*(mxy-mny);
	}
	R(i,0,n) ans=min(ans,v[i]);
}
int Ld[N],Lu[N],Rd[N],Ru[N];

template<class Callable>

void solveofcalc2(int L,int R,int l,int r,Callable cc)
{
	int mid=(l+r)>>1;
	long long mn=3e18;
	int mnp=0;
	R(i,L,R) 
	{
		long long tp=cc(i,mid);
		if(tp<mn) mn=tp,mnp=i;
	}
	v[mid]=mn;
	if(l!=r) solveofcalc2(mnp,R,l,mid,cc),solveofcalc2(L,mnp,mid+1,r,cc);
}
void calc2()
{
	sort(p+1,p+n+1);
	R(i,0,n+5) v[i]=0;
	int mny=1e9,mnyp=0,mxy=-1e9,mxyp=0,mxx=-1e9,mnx=1e9;
	R(i,1,n) 
	{
		if(p[i].second<=mny) mny=p[i].second,mnyp=i;
		if(p[i].second>=mxy) mxy=p[i].second,mxyp=i;
		mxx=max(mxx,p[i].first);
		mnx=min(mnx,p[i].first);
	}
	Ld[0]=1e9,Lu[0]=-1e9;
	Rd[n+1]=1e9,Ru[n+1]=-1e9;
	R(i,1,n) Ld[i]=min(Ld[i-1],p[i].second),Lu[i]=max(Lu[i-1],p[i].second);
	L(i,1,n) Rd[i]=min(Rd[i+1],p[i].second),Ru[i]=max(Ru[i+1],p[i].second);
	if(mnyp>mxyp) swap(mnyp,mxyp);
	auto cc=[&](int x,int y)
	{
		if(x==1&&y==n) return 1ll*(p[y].first-p[x].first)*(mxy-mny);
		return 1ll*(p[y].first-p[x].first)*(mxy-mny)+1ll*(max(Ru[y+1],Lu[x-1])-min(Rd[y+1],Ld[x-1]))*(mxx-mnx);
	};
	solveofcalc2(1,mnyp,mxyp,n,cc);
	R(i,mxyp,n) ans=min(ans,v[i]);
}
int L1[N],L2[N],L3[N],L4[N];
int q[N];
pair<int,int>pq[N];
inline bool cmp(pair<int,int>x,pair<int,int>y)
{
	if(!x.second&&!y.second) return x.first<y.first;
	if((!x.second)^(!y.second)) return !x.second;
	if(!x.first&&!y.first) return x.second<y.second;
	if(1ll*x.first*y.second!=1ll*y.first*x.second) return 1ll*x.first*y.second>1ll*y.first*x.second;
	return x.first<y.first;
}
inline long long calc(pair<int,int>x,pair<int,int>y)
{
	return 1ll*x.first*y.first+1ll*x.second*y.second;
}

struct segt
{
	int rt[N<<2],nd;
	int ls[5555555],rs[5555555];
	pair<int,int> t[5555555];
	void build(int l,int r,int x)
	{
		rt[x]=0;
		if(l==r) return;
		int mid=(l+r)>>1;
		build(l,mid,x<<1);
		build(mid+1,r,x<<1|1);
	}	
	void init(int n)
	{
		R(i,0,nd) ls[i]=rs[i]=0,t[i]=pair<int,int>(0,0);
		nd=0;
		build(1,n,1);
	}
	void insert(int l,int r,pair<int,int> v,int &x)
	{
		if(!x) 
		{
			x=++nd;
			t[x]=v;
			return;
		}
		int mid=(l+r)>>1;
		if(calc(t[x],pq[mid])>calc(v,pq[mid])) swap(t[x],v);
		if(calc(t[x],pq[l])>calc(v,pq[l])) insert(l,mid,v,ls[x]);
		if(calc(t[x],pq[r])>calc(v,pq[r])) insert(mid+1,r,v,rs[x]);
	}
	void insert(int p,int l,int r,pair<int,int> v,int x)
	{
		insert(1,n,v,rt[x]);
		if(l==r) return;
		int mid=(l+r)>>1;
		if(p<=mid) insert(p,l,mid,v,x<<1);
		else insert(p,mid+1,r,v,x<<1|1);
	}
	void query(int p,int l,int r,int x)
	{
		if(!x) return;
		ans=min(ans,calc(t[x],pq[p]));
		int mid=(l+r)>>1;
		if(p<=mid) query(p,l,mid,ls[x]);
		if(mid<p) query(p,mid+1,r,rs[x]);
	}
	void query(int L,int R,int l,int r,int x,int k)
	{
		if(L<=l&&r<=R) return query(k,1,n,rt[x]);
		int mid=(l+r)>>1;
		if(L<=mid) query(L,R,l,mid,x<<1,k);
		if(mid<R) query(L,R,mid+1,r,x<<1|1,k);
	}
}st;
void calc3()
{
	int Mny=1e9,Mxy=-1e9;
	sort(p+1,p+n+1);
	R(i,1,n) Mny=min(Mny,p[i].second),Mxy=max(Mxy,p[i].second);
	int mny=Mxy,mxy=Mny;
	R(i,1,n) L1[i]=p[i].first-p[1].first,L2[i]=mxy-Mny,mxy=max(mxy,p[i].second);
	L(i,1,n) L3[i]=p[n].first-p[i].first,L4[i]=Mxy-mny,mny=min(mny,p[i].second);
	q[0]=0;
	R(i,1,n) q[i]=L2[i];
	sort(q+1,q+n+1);
	R(i,1,n) pq[i]=(L1[i]+L4[i]?pair<int,int>(L1[i],L4[i]):pair<int,int>(1,1));
	sort(pq+1,pq+n+1,cmp);
	st.init(n);
	R(i,1,n)
	{
		int p=lower_bound(q+1,q+n+1,L2[i])-q;
		st.insert(p,1,n,pair<int,int>(L2[i],L3[i]),1);
		p=lower_bound(q+1,q+n+1,Mxy-Mny-L4[i])-q;
		if(L1[i]||L4[i])
		{
			int pp=lower_bound(pq+1,pq+n+1,pair<int,int>(L1[i],L4[i]),cmp)-pq;
			if(p!=n+1) st.query(p,n,1,n,1,pp);
		}
	}
}
void solve()
{
	ans=1e18;
	cin>>n;
	R(i,1,n) cin>>p[i].first>>p[i].second;
	calc1();
	R(i,1,n) swap(p[i].first,p[i].second);
	calc1();
	R(i,1,n) swap(p[i].first,p[i].second);
	calc2();
	calc3();
	R(i,1,n) p[i].second=1e9-p[i].second;
	calc3();
	cout<<ans<<'\n';
}
signed main()
{
	ios::sync_with_stdio(false);
	cin.tie(NULL);
	int _;
	cin>>_;
	while(_--) solve();

}

```

令 $A_i=a_i+2a_{i-1}+a_{i-2},B_i=b_i-2b_{i-1}+b_{i-2}$，然后可以发现对于任意位置 $i$ 进行操作，除了 $A_{i}$ 将会变成 $A_i+1$，其他位置的数值均不变。因此对 $a$ 的操作，对 $A$ 即单点操作。

可以发现，以下条件等同于 $b[1,m]$ 可以与 $a[k+1,k+m]$ 匹配。

$$
\begin{cases}
b_1=a_{k+1}\\
b_1+b_2=a_{k+1}+a_{k+2}\\
B_i=A_{k+i}(i\ge 3)
\end{cases}
$$

对于 $i\le k+2$，对于 $i$ 位置的操作有 $a_{k+1}+a_{k+2}\leftarrow a_{k+1}+a_{k+2}+(-1)^{k-i}$。因此第二个条件限制了前 $k+2$ 位置间奇数位置和偶数位置之间操作次数差异。当对 $i$ 进行操作时，$a_{k+1}\leftarrow a_{k+1}+(k-i+2)\times (-1)^{k-i}$。

于是问题就转化成了使用 $-0,+1,-2,\cdots,(-1)^nn$ 让减法操作次数（使 $a_{k+1}$ 减小的操作）减去加法操作次数为 $a$，并且最后的 $a_{k+1}$ 应该为 $b$。

然后可以观察在某个位置进行一次操作后，$i$ 及 $i+1$ 位置上的数字变化（设其分别为 $x,y$）。

$$
\begin{vmatrix} 
x &  0 &+1&-2&+3&-4\\ 
x+y & +1&-1&+1&-1&+1
\end{vmatrix}
$$

为了方便可以先把所有减法操作做了，之后再撤销（重新添加，即这样均变成加法操作）。这样就得到 $a_{i}+a_{i+1}$ 等于什么，然后就得到了 $x+y,x$ 等于多少，然后前两个条件就可以转化成：$a\leftarrow a+\lfloor\frac{k+1}{2}\rfloor+1,b\leftarrow b+\sum\limits_{i=0}^{\lfloor\frac{k+1}{2}\rfloor} 2i$   其中 $a$ 表示需要选择 $a$ 个（即 $x+y$），$b$ 表示选择的和是 $b$（即 $x$）。

所有满足 $\sum\limits_{i=0}^{a-1} i\le b\le \sum\limits_{i=k+1-a}^{k+1}$ 的 $b$ 都是合法且容易构造出来的。

然后考虑第三个条件，构造函数 $f(k)=\sum\limits_{i=3}^m (B_i-A_{i+k})(B_i-A_{i+k}-1)$。显然 $B_i=A_{i+k}$ 或 $B_i=A_{i+k}+1$ 时上式为 $0$。而 $B_i$ 是否等于 $A_{i+k}$ 代表着我们是否要对 $i+k$ 位置进行操作，即 $B_i=A_{i+k}$ 时不需要操作，$B_i=A_{i+k}+1$ 时进行一次操作， 否则上式一定 $>0$。并且可以发现 $b[1,m]$ 可以与 $a[k+1,k+m]$ 匹配上时一定有 $f(k)=0$。考虑如何计算 $f$。

$$
f(k)=\sum_{i=3}^m A_{i+k}^2+B_i^2-2A_{i+k}B_i-B_i+A_i
$$

对于 $A_{i+k}B_i$，这是一个卷积形式，可以转化为多项式乘法，使用 FFT 求解，而其他项显然是可以简单求出的。

考虑到 $f(k)$ 的值很大，如果使用 NTT，可能需要测试几个不同的素数来避免 hack，这部分时间复杂为 $\mathcal O(n\log n)$。

并且可以通过 bitset 来找到满足第三个条件的 $k$，时间复杂度为 $\mathcal O(\frac{n^2}{\omega})$

```cpp
#include<bits/stdc++.h>
#define ll long long
#define qwq printf("qwq\n");
#define R(i,a,b) for(int i=(a),i##E=(b);i<=i##E;i++)
#define L(i,a,b) for(int i=(b),i##E=(a);i>=i##E;i--)
using namespace std;
const int mod=998244353;
const int _G=646;
const int invG=208611436;
const int G_pw=1<<20;
inline int fix(int a,int p=mod)
{
	a=(a%p+p)%p;
	return a;
}
inline int add(int a,int b,int p=mod)
{
	a+=b;
	if(a>=p) a-=p;
	return a; 
}
inline int dec(int a,int b,int p=mod)
{
	a-=b;
	if(a<0) a+=p;
	return a;
}
inline int mul(int a,int b,int p=mod)
{
	ll c=1ll*a*b%mod;
	return fix(c,p);
}
inline int fpow(int a,int b=mod-2,int p=mod)
{
	int ret=1;
	while(b)
	{
		if(b&1) ret=mul(ret,a,p);
		a=mul(a,a,p);
		b>>=1;
	}
	return ret;
}
inline ll calc(ll l,ll r,ll k)
{
	if(r<l) return 0;
	ll t=(r-l)/k+1;
	ll tmp=1ll*l*t+t*(t-1)/2*k;
	return tmp;
}
inline ll get_mn(ll a,ll b)
{
	b=(a+1)/2-b;
	return calc(1,a,2)-calc(a-b+1,a,1);
}
inline ll get_mx(ll a,ll b)
{
	b=(a+1)/2-b;
	return calc(1,a,2)-calc(1,b,1);
}
struct fu
{
	void NTT(vector<ll>&a,bool rev)
	{
		int n=(int)a.size();
		for(int i=1,j=0;i<n;i++)
		{
			int bit=n>>1;
			for(;j>=bit;bit>>=1) j-=bit;
			j+=bit;
			if(i<j) swap(a[i],a[j]);
		}
		for(int len=2;len<=n;len<<=1)
		{
			int tG=rev?invG:_G;
			for(int i=len;i<G_pw;i<<=1) tG=1ll*tG*tG%mod;
			for(int i=0;i<n;i+=len)
			{
				int w=1;
				for(int j=0;j<len/2;j++)
				{
					int u=a[i+j],v=mul(a[i+j+len/2],w);
					a[i+j]=add(u,v);
					a[i+j+len/2]=dec(u,v);
					w=mul(w,tG);
				}
			}
		}
		if(rev)
		{
			int invn=fpow(n);
			//cout<<invn<<endl;
			R(i,0,n-1) a[i]=mul(a[i],invn);
		}
	}
	vector<ll>poly_mult(vector<ll>a,vector<ll>b)
	{
		int t=(int)(a.size()+b.size());
		int tt=1;
		while(tt<t) tt<<=1;
		vector<ll>c(tt);
		a.resize(tt),b.resize(tt);
		// cout<<"NTT:"<<endl;
		// for(auto x:a) cout<<x<<" ";
		// cout<<endl;
		NTT(a,0),NTT(b,0);

		R(i,0,tt-1) c[i]=mul(a[i],b[i]);
		NTT(c,1);
		return c;
	}
};
int n,m;
bitset<200010>vis;

void solve()
{
	vis.reset();
	cin>>n;
	vector<ll>a(n);
	R(i,0,n-1) cin>>a[i];
	cin>>m;
	vector<ll>b(m);
	R(i,0,m-1) cin>>b[i];
	if(m>2)
	{
		vector<ll>A(n-2),B(m-2),c;
		R(i,0,n-2-1) A[i]=a[i]+2*a[i+1]+a[i+2],c.emplace_back(A[i]);
		R(i,0,m-2-1) B[i]=b[i]+2*b[i+1]+b[i+2],c.emplace_back(B[i]),c.emplace_back(B[i]+1);
		reverse(B.begin(),B.end());
		sort(c.begin(),c.end());
		c.resize(unique(c.begin(),c.end())-c.begin());
		for(ll &x:A) x=lower_bound(c.begin(),c.end(),x)-c.begin()+1;
		for(ll &x:B) x=lower_bound(c.begin(),c.end(),x)-c.begin()+1;

		fu f;
		auto C=f.poly_mult(A,B);
		// for(auto x:C) cout<<x<<" ";
		// cout<<endl; 
		ll s=0;
		R(i,0,m-2-1) s=add(s,mul(A[i],A[i]+1)),s=add(s,mul(B[i],B[i]-1));
		R(i,0,n-m)
		{
			int p=m+i-3;
			if(s!=add(C[p],C[p])) vis[i]=1;
			s=dec(s,mul(A[i],A[i]+1));
			if(i<n-m) s=add(s,mul(A[i+m-2],A[i+m-2]+1));
		}
	}
	R(i,0,n-m) if(!vis[i])
	{
		R(j,0,1)
		{
			ll t=a[i]+a[i+1]-b[0]-b[1]+j;
			if(t>(i+2)/2) continue;
			if(t<-(i+1)/2) continue;
			if(a[i]+get_mn(i+1,t)>b[0]) continue;
			if(a[i]+get_mx(i+1,t)<b[0]) continue;
			R(k,0,m-2-1) if(a[i+k]+2*a[i+k+1]+a[i+k+2]!=b[k]+2*b[k+1]+b[k+2]&&a[i+k]+2*a[i+k+1]+a[i+k+2]+1!=b[k]+2*b[k+1]+b[k+2])
			{
				vis[i]=1;
			}
			if(vis[i]) continue;
			vector<int>ans;
			if(j) ans.emplace_back(i+1);
			R(k,0,m-2-1) if(a[i+k]+2*a[i+k+1]+a[i+k+2]!=b[k]+2*b[k+1]+b[k+2])
			{
				ans.emplace_back(i+k+2);
			}
			ll ddd=b[0]-a[i];
			for(int k=i+1;k>=1;k--)
			{
				ll dc=((k&1)?k:-k),dd=((k&1)?1:-1);
				if(get_mn(k-1,t)<=ddd&&ddd<=get_mx(k-1,t))
				{

				}
				else
				{
					ans.emplace_back(i-k+1);
					ddd-=dc,t-=dd;
				}
			}
			cout<<ans.size()<<'\n';
			for(int x:ans) cout<<x+1<<' ';
			cout<<endl;
			return;
		}
	}
	cout<<-1<<endl;
}	
signed main()
{
	ios::sync_with_stdio(false);
	cin.tie(NULL);
	int _;
	cin>>_;
	while(_--) solve();
}
```

一个显然错误的想法是分别计算 $A,B$ 本质不同的回文串个数，然后将两者相乘，这将会多次计算一个字符串。

因此要思考的问题是，为什么会计算多次？

为了解决这个问题，将用到下面数个引理，如果只是想解决这个问题，建议跳过所有证明。


假设所有字符串的下标从 $0$ 开始。

令 $x^R$ 表示字符串 $x$ 翻转，令 $x^a$ 表示由字符串 $x$ 连续拼接 $a$ 次后的字符串。

令 $t$ 为字符串 $x$ 的一个 border，当且仅当 $x$ 长为 $t$ 的前缀与后缀相同，即 $x{[0,t-1]}=x{[|x|-t,|x|-1]}$。

令 $t$ 为字符串 $x$ 的一个周期，当且仅当 $x_{i}=x_{i+t}(0\le i<|x|-t)$。若 $t \mid |x|
$，则 $t$ 为 $x$ 的一个完全周期。可以发现 $x$ 存在一个长度为 $t$ 的周期当且仅当 $x$ 有一个长为 $|x|-t$ 的 border。

令 $border(x) $ 为 $x$ 最长的 border。

可以发现，若 $x$ 是回文串，则他的回文前缀与后缀均为 $x$ 的 border。

因此 $border(x)$ 为 $x$ 的最长回文前缀（后缀）。

证明：

假设 $a$ 为 $x$ 的一个 border，即 $x_i=x_{|x|-a+i}(0\le i\le a-1)$。且 $x$ 有长为 $a$ 的回文前缀 $x_i=x_{a-1-i}(0\le i\le a-1)$，因此 $x_i=x_{|x|-i-1}$，满足 $x$ 为回文串。

若 $S=xy$，$x,y$ 为两个非空回文串，则 $(x,y)$ 为 $S$ 的一组回文分解。

若 $S=xy$，$x,y$ 均为回文串且 $y$ 非空，则 $(x,y)$ 为一组非严格回文分解。

若字符串 $x$ 的最小完全周期长度 $\neq |x|$，则称 $x$ 为循环串。

引理 1:

如果 $p,q$ 均为 $s$ 的一个周期，且 $p+q\le |s|$，则 $\gcd(p,q)$ 同样也是 $s$ 的一个周期。

证明：

假设 $p<q,d=q-p$

$s_i=s_{i-p}=s_{i+d}(|s|-q\le i<|s|-d)$.

$s_i=s_{i+q}=s_{i+q-p}=s_{i+d}(0\le i<|s|-q)$.

因此 $q-p$ 也是一个周期，根据欧几里得算法可以得到 $\gcd(p,q)$ 同样也是一个周期。

引理 2：

令 $S$ 表示字符串 $s$ 所有 $\le \frac{|s|}{2}$ 周期的集合，如果 $S$ 非空，则 $\forall u\in S,\min S\mid u$。

证明：

令 $v=\min S$，显然 $u+v\le|s|$，根据引理 1，$\gcd(u,v)$ 同样属于集合 $S$，所以 $\gcd(u,v)\ge v,v\mid u$。

引理 3：

若 $S=x_1x_2=y_1y_2=z_1z_2,|x_1|<|y_1|<|z_1|$，$x_2,y_1,y_2,z_1$ 均为非空回文串，则 $x_1,z_2$ 均为回文串。

证明：

令 $z_1=y_1v$，显然 $v^R$ 为 $y_2$ 的一个后缀，同样也是 $x_2$ 的一个后缀。

因为 $x_2$ 为回文串，因此 $v$ 为 $x_2$ 的前缀，所以 $x_1v$ 是 $z_1$ 的一个前缀。

又因为 $y_1$ 是 $z_1$ 的回文前缀，所以 $|v|$ 为 $z_1$ 的一个周期，即 $|v|$ 为 $x_1v$ 的一个周期。

假设 $t$ 为一个任意大的数，即 $x_1$ 为 $v^t$ 的后缀。

因为 $v^R$ 为 $z_1$ 的前缀，$x_1$ 为 $(v^R)^t$ 的前缀。所以 $x_1^R$ 为 $v^t$ 的一个后缀，因此 $x_1$ 为回文串。

引理 4：

若串 $S$ 存在回文分解，令 $a$ 表示 $S$ 的最长回文前缀，$S=ax$，$b$ 表示 $S$ 的最长回文后缀，$S=yb$，则 $x,y$ 中必然有一个是回文串。

证明：

假设 $x,y$ 均不是回文串，令 $p,q$ 为 $S$ 的一个回文分解，因此 $S=yb=pq=ax$，根据引理 3，这显然不成立。

引理 5：

若 $S=p_1q_1=p_2q_2$（$|p_1|<|p_2|$，且 $p_1,p_2,q_1,q_2$ 均为回文，$q_1,q_2$ 非空），则 $S$ 是一个循环串。

证明：

可以发现 $\gcd(|p_2|-|p_1|,|S|)$ 是 $S$ 的一个周期。

因为 $p_1$ 是 $p_2$ 的一个回文前缀，所以 $p_2,q_1$ 均有周期 $|p_2|-|p_1|$。由于 $[p_1,p_2-1]$ 这部分被重复覆盖，因此 $S$ 也有周期 $|p_2|-|p_1|$。

$\forall x\in[0,t),S_x=S_{|p_2|-1-x}=S_{|S|-1+|p_1|-(|p_2|-1-x)}=S_{|S|-|p_2|+|p_1|+x}$

因此 $|S|-(|p_2|-|p_1|)$ 为 $S$ 的一个周期。根据引理 1，$\gcd(|p_2|-|p_1|,|S|)\mid |S|$，所以 $|S|$ 是一个循环串。

引理 6：

令 $S=p_1q_1=p_2q_2=\cdots=p_tq_t$ 是所有 $S$ 的非严格分解，令 $h$ 表示最小完全周期。若 $t\ne 0$，则 $t=\frac{|S|}{h}$。

证明：

根据引理 5，当 $t=1$ 时 $h=|S|$，于是接下来只讨论 $t\ge 2$。

令 $\alpha =S[0,h-1]$，显然 $\alpha$ 并不是循环串（否则 $S$ 就会有一个更小的完全周期），因此 $\alpha$ 最多有一个非严格分解。


令 $S=pq$ 为一组非严格分解，存在 $\max(|p|,|q|)\ge h$。

当 $|p|\ge h$ 时，$\alpha=p[0,h-1]$，因为 $\alpha[0,|p|\bmod h-1]=p^R[0,|p|\bmod h-1]=(\alpha[0,|p|\bmod h-1])^R$，因此 $\alpha[0,|p|\bmod h-1]$ 为回文串。类似的，$\alpha[|p|\bmod h-1,h-1]$ 同样也是回文的。

$|q|\ge h$ 时同理。所以 $\alpha[0,|p|\bmod h-1],\alpha[|p|\bmod h-1,h-1]$ 为 $\alpha$ 的非严格回文分解。


因此 $\alpha$ 具有非严格回文分解，假设唯一的非严格回文分解为 $\alpha[0,g-1],\alpha[g,h-1]$。所以所有 $p_i$ 必须满足 $p_i\bmod h=g$，所以 $t\le \frac{|S|}{h}$，并且这 $\frac{|S|}{h}$ 种 $p_i$ 都是合法的。

引理 7：

令 $S=p_1q_1=p_2q_2=\cdots=p_tq_t(|p_i|<|p_{i+1}|)$ 是所有 $S$ 的非严格分解。则 $\forall i \in [1,t-1]$，$p_i=border(p_{i+1})$ 与 $q_{i+1}=border(q_i)$ 至少有一项成立。
至少有一项成立。

证明：

先直接考虑如何求出所有非严格回文分解。

假设 $S$ 的最长回文前缀为 $a(a\ne S),S=ax$，最长回文后缀为 $b$（$b$ 有可能为 $S$）$S=yb$。

若 $x=b$，显然 $S=ab$ 为唯一的分解方法。

若 $S=pq$ 并且 $p\ne a,q\ne b$，$p,q$ 均为回文，根据引理 3，可以得到 $x,y$ 均为回文串。

因此若 $x,y$ 均不为回文，则 $S$ 不存在非严格回文分解  

若 $x,y$ 中只有一个为回文串，则 $S$ 只存在唯一一种非严格回文分解。

若 $x,y$ 均为回文串，然后可以找到第二长的非自回文前缀 $c,S=cz$，若 $z$ 不是回文串或 $c=y$，则 $S=ax=yb$ 是唯二合法的分解。

否则 $z$ 是回文串，可以找出所有长度介于 $|z|$ 与 $b$ 之间的回文后缀，它们对应的前缀也一定是回文的（引理 3）。因此就求出了所有非严格回文分解（由于回文后缀长度不会大于 $|b|$，回文前缀长度不会大于 $|a|$，因此这样求出的回文分解是不漏的）

重新考虑如何证明，对于非 $S=ax=yb$ 这种情况，可以发现对于 $(c,z),(a,x)$ 满足 $p_i=border(p_{i+1})$，其余均满足 $q_i=border(q_{i+1})$。

然后考虑如何证明 $S=ax=yb$ 这种情况引理依然成立。

先假设这种情况是错误的，令 $p=border(a),s=border(b),S=ax=pq=rs=yb$（$|a|>|p|>|y|,|a|>|r|>|y|$，$p,s$ 均为回文串）

根据引理 6，可以得到 $S$ 只有两种非严格回文分解，且 $S=\alpha^2$。

若 $|p|\ge |\alpha|$，有 $q=\alpha[|p|\bmod h,h-1]$，因此 $q$ 也是一个回文串，矛盾。

因此有 $|p|<|\alpha|$，同样可以得到 $|s|<|\alpha|$，令 $\alpha=pq'=r's$，并且根据引理 6，令 $\alpha$ 唯一的非严格分解为 $\beta\theta$。因此根据引理 3 可得到 $q'$ 和 $r‘$ 也是一个回文串，矛盾。

根据引理 7，假设 $S=xy$，如果用 $border(x)$ 代替 $x$ 或 $border(y)$ 代替 $y$ 后也能拼出 $S$，那么 $S$ 将会被重复计算，答案需要减 1。

所以对于 $A$ 中的一个回文串 $x$，我们需要计算从 $x$ 和 $border(x)$ 中都可以拼出的字符串 $S$ 并从答案中减去。其中找 $x$ 和 $border(x)$ 都可以通过回文树完成。

令 $x=border(x)w$，需要计算的就是在 $B$ 中有多少 $T$ 满足 $T=wS$，且 $S,T$ 均为 $B$ 中的回文串。因为 $|w|$ 是 $x$ 的最短周期，因此 $w$ 不是循环串。

若 $|w|>|S|,w=S+U$，其中 $S,U$ 均为回文串。且因为 $w$ 不是一个循环串，所以 $w$ 最多有一个非严格回文分解（引理5）。我们只需验证这个非严格回文分解是否包含 $w$ 的最长前缀和后缀，然后通过 hash 验证 $S$ 和 $wS$ 是否在 $B$ 中存在即可。

若 $|w|\le |S|$，若 $S$ 不是 $T$ 的最长回文后缀，则 $w$ 一定是循环串（引理 2)，矛盾。

因此只需要对所有最长回文后缀（即 $S=border(T)$ 且 $(|T|-|S|\times 2 \le |T|$）的位置判断一遍即可，可以通过 hash 实现。

找子串的最大回文前缀和后缀可以通过对两棵回文树（一棵正常和一棵翻转）倍增，令 $up_{i,j}$ 表示从节点 $i$ 跳 fail 链 $2^j$ 步后的节点。在查询 $s[l,r]$ 的最大回文后缀时，找到对应 $s[1,r]$ 的最大回文后缀的节点。如果就是包含与 $[l,r]$区间，这就是答案。否则，从大到小枚举枚举 $j$ 找合适的即可。

然后再对 $B$ 同样做一遍，注意需要加上既会被 $border(x)$ 计算，又会被 $border(y)$ 计算的这部分。

```cpp
#include<bits/stdc++.h>
#define ll long long
#define qwq printf("qwq\n");
#define R(i,a,b) for(int i=(a),i##E=(b);i<=i##E;i++)
#define L(i,a,b) for(int i=(b),i##E=(a);i>=i##E;i--)
using namespace std;
const int base1=1379973;
const int base2=3771931;
const int mod1=1e9+7;
const int mod2=1e9+9;

int pw1[222222],pw2[222222];
char A[222222],B[222222];
int n,m;
ll ans;

struct hashing
{
    ll x,y;
    inline hashing (ll X=0,ll Y=0):x(X),y(Y) {}
    inline hashing nxt(int a)
    {
        return hashing(x*pw1[a]%mod1,y*pw2[a]%mod2);
    }
    inline hashing operator +(const char a)
    {
        return hashing((x+a)%mod1,(y+a)%mod2);
    }
    inline hashing operator +(const hashing a)
    {
        return hashing((x+a.x)%mod1,(y+a.y)%mod2);
    }
    inline hashing operator -(const hashing a)
    {
        return hashing((x-a.x+mod1)%mod1,(y-a.y+mod2)%mod2);
    }
    inline ll val()
    {
        return x*mod2+y;
    }
};
const ll hs=1235287;
struct hashtable
{
    ll head[hs+10],cnt;
    struct edge
    {
        ll nxt;
        ll key,val;
    }e[666666];
    inline ll hash(ll x)
    {
        return (x%hs+hs)%hs;
    }
    inline void add_edge(ll u,ll v,ll d)
    {
        e[++cnt]=(edge){head[u],v,d};head[u]=cnt;
    }
    inline int get_val(ll x)
    {
        ll h=hash(x);
        for(int i=head[h];i;i=e[i].nxt) 
            if(e[i].key==x) return e[i].val;
        return 0;
    }
    inline void ins(ll x,ll d)
    {
        ll h=hash(x);
        for(int i=head[h];i;i=e[i].nxt)
        {
            if(e[i].key==x) 
            {
                e[i].val=d;
                return;
            }
        } 
        add_edge(h,x,d);
    }
};

struct PalindromicTree
{
    hashtable mxlen,hst;
    hashing hs1[222222],hs2[222222];
    char s[222222];
    int n,tot,to[222222][26];
    int fil[222222],diff[222222],slink[222222],len[222222];
    int mnp[222222];
    ll phs1[222222],phs2[222222];
    pair<int,int>seg[222222];
    int append(int n,int p)
    {
        int c=s[n]-'a';
        while(s[n-1-len[p]]!=s[n]) p=fil[p];
        if(to[p][c]) return to[p][c];
        int q=++tot;
        len[q]=len[p]+2;
        seg[q]={n-len[q]+1,n};
        int f=fil[p];
        while(s[n-1-len[f]]!=s[n]) f=fil[f];
        fil[q]=to[f][c];
        to[p][c]=q;
        diff[q]=len[q]-len[fil[q]];
        slink[q]=diff[q]==diff[fil[q]]?slink[fil[q]]:fil[q];
        return q;
    }
    int st[222222];
    ll geths2(int l,int r,int l2,int r2)
    {
        return ((hs1[r]-hs1[l-1].nxt(r-l+1)).nxt(r2-l2+1)+hs1[r2]-hs1[l2-1].nxt(r2-l2+1)).val();
    }
    ll geths(int l,int r)
    {
        return (hs1[r]-hs1[l-1].nxt(r-l+1)).val();
    }
    ll gethss(int l,int r)
    {
        return (hs2[l]-hs2[r+1].nxt(r-l+1)).val();
    }
    void construct(int _n,char _s[])
    {
        n=_n;
        hs1[0]=hashing(0,0);
        R(i,1,n) s[i]=_s[i],hs1[i]=hs1[i-1].nxt(1)+s[i];
        hs1[n+1]=hashing(0,0);
        L(i,1,n) hs2[i]=hs2[i+1].nxt(1)+s[i];
        int p=0;
        fil[0]=1,len[0]=0,seg[0]={1,0};
        fil[1]=0,len[1]=-1,seg[1]={1,0};
        tot=1;
        st[0]=p;
        R(i,1,n)
        {
            p=append(i,p);
            st[i]=p;
        }
        R(i,2,tot)
        {
            hst.ins(geths(seg[i].first,seg[i].second),1);
            mnp[i]=len[i]-len[fil[i]];
            phs1[i]=geths(seg[i].first,seg[i].first+mnp[i]-1);
            phs2[i]=gethss(seg[i].first,seg[i].first+mnp[i]-1);
            if(len[i]>=mnp[i]*2) mxlen.ins(phs1[i],max(mxlen.get_val(phs1[i]),len[i]/mnp[i]-1));
        }
    }
    int query_mxp(int p,int b)
    {
        if(b>len[p]) return len[p];
        while(1)
        {
            int l=len[slink[p]];
            int d=diff[p];
            if(b>=l) return ((b-l)/d)*d+l;
            p=slink[p];
        }
    }
}t1,t2,t11,t22;
void init()
{
    t1.construct(n,A);
    t2.construct(m,B);
    ans=1ll*(t1.tot-1)*(t2.tot-1);
    reverse(A+1,A+n+1);
    reverse(B+1,B+m+1);
    t11.construct(n,A);
    t22.construct(m,B);
    reverse(A+1,A+n+1);
    reverse(B+1,B+m+1);
}
inline bool is_pal(int l,int r)
{
    return t1.query_mxp(t1.st[r],r-l+1)==r-l+1;
}
void check_pal_deco(int l,int r)
{
    int p=t1.query_mxp(t1.st[r],r-l+1);
    if(l<=r-p&&r-p<r&is_pal(l,r-p))
    {
        ans-=t2.hst.get_val(t1.geths2(l,r,l,r-p));
        return;
    }
    p=t11.query_mxp(t11.st[n-l+1],r-l+1);
    if(l<l+p&&l+p<=r&&is_pal(l+p,r))
    {
        ans-=t2.hst.get_val(t1.geths2(l,r,l,l+p-1));
        return;
    }
}
unordered_map<ll,int>mp;

void calc(int opt)
{
    R(i,2,t1.tot)
    {
        int p=t1.mnp[i];
        if(t1.len[i]<=p) continue;
        int cnt=t2.mxlen.get_val(t1.phs2[i]);
        ans-=cnt;
        check_pal_deco(t1.seg[i].second-p+1,t1.seg[i].second);
        if(!opt) mp[t1.phs1[i]]++;
        else ans+=mp[t1.phs2[i]];
    }
}

signed main()
{
    pw1[0]=pw2[0]=1;
    R(i,1,200005) pw1[i]=1ll*pw1[i-1]*base1%mod1,pw2[i]=1ll*pw2[i-1]*base2%mod2;
    scanf("%s%s",A+1,B+1);
    n=strlen(A+1),m=strlen(B+1);
    init();
    calc(0);
    swap(A,B);
    swap(n,m);
    swap(t1,t2);
    swap(t11,t22);
    calc(1);
    printf("%lld\n",ans);
}
```

反正可以直接当 $k=3$ 去做，然后考虑直接去构造。

首先任意给树找一个根，然后将整棵树拆成几个大小为 $\sqrt n$ 的子树，将所有这些子树的根 $u$ 塞到一个点集 $a$ ，然后将 $a$ 中的点相互连接，边的数量为 $\mathcal O(n)$。

接着，对于点集 $a$ 中的每个点 $u$，将 $u$ 与其子树中的每个点连接，显然边数仍然为 $\mathcal O(n)$。

最后，再对所有子树递归这个过程即可。由于最多有 $\mathcal O(\log \log n)$ 次递归，每次边数都是 $\mathcal O(n)$，因此总边数是 $\mathcal O(n\log \log n)$ 的。

然后来证明一下为什么这样最长路径为 $3$，考虑两个顶点 $u,v$ 以及它们在同一子树时的最后一次递归。令 $c(x)$ 为与子树 $x$ 相邻且属于 $a$ 中的点，显然在上述构造下，若 $c(u)\ne c(v)$，则 $c(u)$ 与 $c(v)$ 一定有边直接相连。若 $c(u)=c(v)$ 则路径更短。因此最长路径为 $3$。

```cpp
int n,k;
int vis[11111],viss[11111],siz[11111];
vector<int>e[11111],st,at;
vector<pair<int,int> >ans;
void dfs3(int u,int n)
{
	vis[u]=1;
	for(int v:e[u]) if(!vis[v]&&!viss[v])
	{
		dfs3(v,n);
		siz[u]+=siz[v];
	}
	if(siz[u]>=n)
	{
		viss[u]=1;
		siz[u]=0;
		at.emplace_back(u);
	}
}
void dfs2(int u)
{
	st.emplace_back(u);
	vis[u]=1;
	for(int v:e[u]) if(!vis[v]&&!viss[v]) dfs2(v);
}
void dfs1(int u)
{
	st.clear();
	dfs2(u);
	int sz=st.size();
	int sz2=floor(sqrt(sz));
	for(int x:st) vis[x]=0,siz[x]=1;
	if(sz<=4) 
	{
		for(int x:st) viss[x]=1;
		return;
	}
	at.clear();
	dfs3(u,sz2);
	for(int x:st) vis[x]=0;
	for(int x:at) for(int y:at) if(x<y)
	{
		ans.emplace_back(x,y);
	} 
	vector<int>st2=st;
	for(int x:at)
	{
		st.clear();
		dfs2(x);
		for(int y:st)
		{
			if(x!=y) ans.emplace_back(x,y);
			vis[y]=0;
		}
	}
	for(int x:st2) if(!viss[x]) dfs1(x);
}
signed main()
{
	ios::sync_with_stdio(false);
	cin.tie(NULL);
	cin>>n>>k;
	R(i,1,n-1)
	{
		int x,y;
		cin>>x>>y;
		e[x].emplace_back(y);
		e[y].emplace_back(x);
	}
	dfs1(1);
	cout<<ans.size()<<'\n';
	for(auto [x,y]:ans) cout<<x<<" "<<y<<'\n';
}	
```

简要题意：

定义三维空间中的一个 lattice 是满足下列条件的三维整点的集合：

$$
L=\{u\cdot \overrightarrow{r_1}+v\cdot \overrightarrow{r_2}+w\cdot \overrightarrow{r_3} \}_{u,v,w\in \mathbb Z}
$$

其中 $\overrightarrow{r_1},\overrightarrow{r_2},\overrightarrow{r_3}$ 为三维空间中的整系数坐标向量，满足：

1. $\overrightarrow{r_1},\overrightarrow{r_2},\overrightarrow{r_3}$ 两两正交，即

$$
\overrightarrow{r_1}\cdot \overrightarrow{r_2}=\overrightarrow{r_1}\cdot \overrightarrow{r_3} =\overrightarrow{r_2}\cdot \overrightarrow{r_3}=0
$$

2. $\overrightarrow{r_1},\overrightarrow{r_2},\overrightarrow{r_3}$ 长度相等，即

$$
|\overrightarrow{r_1}|=|\overrightarrow{r_2}|=|\overrightarrow{r_3}|
$$

现在由有 $n$ 个三维整点构成的的集合 $A=\{\overrightarrow{a_1},\overrightarrow{a_2},\cdots,\overrightarrow{a_n} \}$ ，其中 $\overrightarrow{a_i}=(x_i,y_i,z_i)$。

你需要找到一个 lattice L 满足 $A⊂ L$ 且组成 $L$ 的三个基向量尽可能大。

sol：

二维平面上的变换一般使用复数来刻画，其中相当于整数在实数中地位的，被称为 Gauss 整数（即 $a+b\text{i}$ 其中 $a,b\in \mathbb Z$）。所有 Gauss 整数关于 $+$ 和 $\times$ 的算构成一个 Euclid 整环。

先考虑一个简化的二维版本：

可以发现所有 $a_i$ 可以被拆成两个高斯整数的乘积，即 $a_i=b_i\cdot g$，其中 $g=(\overrightarrow{r_1},\overrightarrow{r_2})$。而要找到最大的 $g$ 可以直接通过 Euclid 算法完成。

然后来考虑三维空间：

根据第一个条件，可以发现  $\overrightarrow{r_3}$ 与 $\overrightarrow{r_1}\times \overrightarrow{r_2}$ 是共线向量。

而又因为 $|\overrightarrow{r_1}\times \overrightarrow{r_2}|=r^2,|\overrightarrow{r_3}|=r$，说明 $\overrightarrow{r_1}\times \overrightarrow{r_2}=\pm r\cdot \overrightarrow{r_3}⇒ r\in \mathbb N^{*}$ 。

（即 $\overrightarrow{r_3}$ 可以用 
{% raw %}
$\overrightarrow{r_3}=\pm \frac{\overrightarrow{r_1}\cdot \overrightarrow{r_2}}{|r_1|} $
{% endraw %}
 表示）

并且，由于 $\overrightarrow{a}=u\cdot \overrightarrow{r_1}+v\cdot \overrightarrow{r_2}+w\cdot \overrightarrow{r_3}$，则 $|\overrightarrow{a}|^2=(u^2+v^2+w^2)\cdot r^2⇒r^2 |(|\overrightarrow{a}|^2)$

即 $r$ 需要满足 $r^2|\gcd(x_1^2+y_1^2+z_1^2,x_2^2+y_2^2+z_2^2,\cdots ,x_n^2+y_n^2+z_n^2)$。

并且因为满足这个条件的 $r$ 数量不多，所以可以对 $r$ 从大到小逐个检验是否合法。

而在三维空间中的变换，一般使用四元数 $a+b\text{i}+c\text{j}+d\text{k}$ 来刻画，而在四元数中有整数地位的，被称为 Lipschitz 四元数。（四元数的运算满足结合律，不满足交换律，$\text i^2=\text j ^2 =\text k ^2=ijk=-1$

但是这样定义出来的四元数集合不构成 Euclid 整环，而这道题中的操作类似于 $\gcd$ 的过程，因此需要扩充一下定义，考虑增加部分有理四元数。

在复数中，$|a+b\text i|=\sqrt{a^2+b^2}$，会有一些满足 $a^2+b^2\in\mathbb Z$，这样就会有一些形如 $\frac 4 5+\frac 3 5 \text i$ 的东西，虽然模长为整数，但是可以和 $1,\text i$ 整系数表示出 $\frac{1+\text i}{5}$，模长就不为整数。

于是在 $\mathbb C$ 中，如果能扩充的话，肯定要考虑 $a+b\text i$，其中 $\frac 1 a,\frac 1 b\in{\mathbb Z}$。那么在这种情况情况下，除了 $a=b=1$，其余所有的有理复数模长均不等于 $1$，因此不能扩充。

但是，这件事搬到四元数 $\mathbb H$ 中就不一样了，可以发现 $a=b=c=d=2$ 时，$|\frac{1+\text i +\text j +\text k}2|=1$。

因此，如果将 $\omega=\frac{1+\text i+\text j+\text k}2$ 加入 Lipschitz 四元数集合，并取正系数表示，就得到了Hurwitz 四元数：

$$
H=\{a+b\text i+c\text j+d\text k|a,b,c,d\in \mathbb{Z}\vee a,b,c,d\in\mathbb Z+\frac 1 2 \}
$$

可以证明，虽然没有交换律，但是 $H$ 中依然有类似地唯一分解定理，可以做 Euclid 算法。

具体地，在 $H$ 中，对于两个数 $A,B$，可以定义它的左商、左余数，右商、右余数，以及左 $\gcd$ 和右 $\gcd$。如，左商和左余数对应表达式 $A=qB+r$，而左 $\gcd $ 就表示模最大的 $d$ 满足 $A=du,B=dv$。

有了 Hurwitz 四元数后，整个问题就清晰了很多：

首先对于三维空间中的向量 $\overrightarrow a=(x,y,z)$ ，对应到四元数 $A=x\text i+y\text j+z\text k$。那么三维空间中其中一组标准的正交基就可以表示为 $\text{i,j,k}$。

根据立体几何，三维空间中的旋转变换可以这样表示：

$$
\overrightarrow{v}↦k\cdot \frac{q\cdot \overrightarrow v\cdot \overline q}{q\cdot \overline q}=k\cdot \frac{q\cdot \overrightarrow v\cdot \overline q}{|q|^2}
$$

其中 $\overrightarrow v$ 表示实部为 $0$ 的四元数，$q=a+b\text i+c\text j+d\text k$ 为一个特定的四元数，$\overline q$ 为 $q$ 的共轭 $\overline q=a-b\text i -c\text j-d\text k$。

于是，$\overrightarrow{r_1},\overrightarrow{r_2},\overrightarrow{r_3}$ 都可以看成标准正交基经过某个旋转并缩放后的结果，因此有：


{% raw %}
$$
\begin{cases} 
\overrightarrow{r_1} =r\cdot \frac{q\cdot \text i\cdot \overline{q}}{|q|^2}\\
\overrightarrow{r_2} =r\cdot \frac{q\cdot \text j\cdot \overline{q}}{|q|^2}\\
\overrightarrow{r_3} =r\cdot \frac{q\cdot \text k\cdot \overline{q}}{|q|^2}\\
\end{cases}

$$
{% endraw %}




然后可以发现 $x=\frac{k}{|q|^2}=\frac{k}{a^2+b^2+c^2+d^2}$ 的分母是 $4$ 的约数。

具体证明：

首先还是这个式子 $\overrightarrow{v}↦k\cdot \frac{q\cdot \overrightarrow v\cdot \overline q}{q\cdot \overline q}$。

考虑写成矩阵形式：

$$
\frac{k}{a^2+b^2+c^2+d^2}\cdot 
\begin{pmatrix} 
a^2+b^2-c^2-d^2 & 2cb-2ad & 2ac+2bd\\ 
2ad+2bc & a^2-b^2+c^2-d^2 & 2cd-2ab\\
2bd-2ac & 2ab+2cd & a^2-b^2-c^2+d^2\\
\end{pmatrix}
$$

显然矩阵中所有元素均为整数。因此分数 $\frac{k}{a^2+b^2+c^2+d^2}$ 应该整除于所有矩阵元素。不失一般性，可以假设 $\gcd(a,b,c,d)=1$（否则可以让 $a,b,c,d$ 除以这个数使四元数坐标减小，并且矩阵元素不变）。假设 $\frac{k}{a^2+b^2+c^2+d^2}=\frac{P}{Q}$，则 $Q$ 要整除于所有矩阵元素， 并且整除于 $a^2 +b^2+c^2+d^2$，即整除于：

$$
\gcd 
\begin{pmatrix} 
a^2+b^2+c^2+d^2\\ 
a^2+b^2-c^2-d^2 \\
a^2-b^2+c^2-d^2 \\
a^2-b^2-c^2+d^2
\end{pmatrix}
=\gcd
\begin{pmatrix} 
a^2+b^2+c^2+d^2\\ 
2(c^2+d^2) \\
2(b^2+d^2) \\
2(b^2+c^2)
\end{pmatrix}
=\gcd
\begin{pmatrix} 
a^2+b^2+c^2+d^2\\ 
2(c^2+d^2) \\
2(b^2+d^2) \\
4d^2
\end{pmatrix}
$$

（$\gcd(a\pm b,b)=\gcd(a,b)=\gcd(-a,b)$）

并且由于 $\gcd(a,b)$ 整除于 $\gcd(k\cdot a,b)$，因此 $Q$ 整除于：

$$
\gcd
\begin{pmatrix} 
4(a^2+b^2+c^2+d^2)\\ 
4(c^2+d^2) \\
2(b^2+d^2) \\
4d^2
\end{pmatrix}
=4\gcd (a^2,b^2,c^2,d^2)=4
$$

因此 $\overrightarrow{v}↦k\cdot \frac{q\cdot \overrightarrow v\cdot \overline q}{4}$。

如果放宽条件 $x\in H$，则进一步可说明 $x$ 的分母是 $2$ 的约数，即 $2x\in\mathbb Z$。通过适当调整使得 $q$ 为 Lipschitz 四元数 ，根据题目条件可得到 $x=1$。

定义 $f(v)=q\cdot v\cdot \overline{q}$，那么存在一组向量  $\overrightarrow{b_1},\overrightarrow{b_2},\cdots,\overrightarrow{b_n}$ 满足

$$
\overrightarrow{a_i}=f(\overrightarrow{b_i})=q\cdot \overrightarrow{b_i} \cdot \overline{q}
$$

于是，此时有 $q|\overrightarrow{a_i}$ ，因此 $q|\gcd(\overrightarrow{a_1},\overrightarrow{a_2},\cdots,\overrightarrow{a_n})$。

并且还枚举了 $r$，因此必须有 $|q|^2=r$，由唯一分解定理可得到 $q|r$。

于是 $q|\gcd(\overrightarrow{a_1},\overrightarrow{a_2},\cdots,\overrightarrow{a_n},r)$。事实上，设 $q_0=\gcd(\overrightarrow{a_1},\overrightarrow{a_2},\cdots,\overrightarrow{a_n},r)$ ，则 $|q_0|^2|r$，因此只有当 $|q_0|^2=r$ 时才有必要验证下去。

之后就只需要反解出 $\overrightarrow{b_i}=\frac{q\cdot \overrightarrow{a_i}\cdot \overline q}{r^2}$ 并检验是否是整数即可。

```cpp
#include<bits/stdc++.h>
#define int long long
#define ll long long
#define ld long double
#define R(i,a,b) for(int i=(a),i##E=(b);i<=i##E;i++)
#define L(i,a,b) for(int i=(b),i##E=(a);i>=i##E;i--)
const ld eps=1e-10l;
using namespace std;

struct qua
{
	ld a,b,c,d;
	inline qua(ld A=0,ld B=0,ld C=0,ld D=0):a(A),b(B),c(C),d(D) {}
	inline qua operator + (qua A) 
	{
		return qua(a+A.a,b+A.b,c+A.c,d+A.d);
	}
	inline qua operator - (qua A)
	{
		return qua(a-A.a,b-A.b,c-A.c,d-A.d);
	}
	inline qua operator * (qua A)
	{
		return qua(
			a*A.a-b*A.b-c*A.c-d*A.d,
			a*A.b+b*A.a+c*A.d-d*A.c,
			a*A.c-b*A.d+c*A.a+d*A.b,
			a*A.d+b*A.c-c*A.b+d*A.a
		);
	}
	inline qua conj()//共轭
	{
		return qua(a,-b,-c,-d);
	}
	inline ld norm()//|q|^2
	{
		return a*a+b*b+c*c+d*d;
	}
	inline qua inv()
	{
		return conj()*qua(1.l/norm());
	}
	inline int check_int()
	{
		return fabsl(roundl(a)-a)<eps&&fabsl(roundl(b)-b)<eps&&fabsl(roundl(c)-c)<eps&&fabsl(roundl(d)-d)<eps;
	}
	inline qua qround()
	{
		qua q1=qua(roundl(a),roundl(b),roundl(c),roundl(d));
		qua q2=qua(floorl(a)+.5l,floorl(b)+.5l,floorl(c)+.5l,floorl(d)+.5l);
		return (q1-*this).norm()<(q2-*this).norm()?q1:q2;
	}
	inline qua operator / (qua A)
	{
		return A.inv() * *this;
	}
	inline qua operator % (qua A)
	{
		qua ret=(*this/A).qround();
		return *this-A*ret;
	}
	inline void printf()
	{
		cout<<b<<" "<<c<<" "<<d<<'\n';
	}
	inline void print()
	{
		cout<<llroundl(b)<<" "<<llroundl(c)<<" "<<llroundl(d)<<'\n';
	}
}a[11111],g;
qua gcd(qua a,qua b)
{
	return b.norm()<eps?a:gcd(b,a%b);
}
ll gcd(ll a,ll b)
{
	return !b?a:gcd(b,a%b);
}

int n;
ll G;
vector<ll>v;
signed main()
{
	ios::sync_with_stdio(false);
	cin.tie(NULL);
	cin>>n;
	R(i,1,n)
	{
		cin>>a[i].b>>a[i].c>>a[i].d;

		g=gcd(g,a[i]);
		G=gcd(G,(ll)a[i].norm());
	}
	for(ll i=1;i*i<=G;i++) if(G%(i*i)==0) v.emplace_back(i);
	reverse(v.begin(),v.end());
	for(auto x:v)
	{
		qua q=gcd(g,qua(x));
		ll r=(ll)q.norm();
		if(r!=x) continue;
		qua q0=q.conj() / qua(r * r);
		int ok=1;
		R(i,1,n) if((q0*a[i]*q).check_int()==0)
		{
			ok=0;
			break;
		}
		if(ok)
		{
			cout<<r*r<<'\n';
			(q*qua(0,1)*q.conj()).print();
			(q*qua(0,0,1)*q.conj()).print();
			(q*qua(0,0,0,1)*q.conj()).print();
			return 0;
		} 
	}
}
