    head[u]=cnt;
    e[++cnt]=(edge){u,head[v],0};
    head[v]=cnt;
}
int bfs()
{
    memset(dis,-1,sizeof(dis));
    int h=0,t=1;
    q[1]=S;dis[S]=0;
    while(h!=t)
    {
        int u=q[++h];
