}
int dfs(int u,int flow)
{
    if(u==T) return flow;
    int del=flow;
    for(int i=head[u];i&&del;i=e[i].nxt)
    {
        int v=e[i].to;
        if(dis[v]==dis[u]+1&&e[i].f)
        {
            int k=dfs(v,min(e[i].f,del));
            e[i].f-=k;
            e[i^1].f+=k;
            del-=k;
        }
    }
    if(del) dis[u]=-1;
    return flow-del;
}
