### 毒瘤之神的考验

#### 题意

多测。求
$$
\left(\sum_{i=1}^n \sum_{j=1}^m \varphi(ij) \right)\bmod 998244353
$$
$T\le 10^4,n,m\leq 10^5$。

#### sol

两个结论
$$
d(nm)=\sum_{i\mid n} \sum_{j\mid m} [\gcd(i,j)=1]
$$

$$
\varphi(nm)=\frac{\varphi(n)\varphi(m)\gcd(n,m)}{\varphi\left(\gcd(n,m)\right)}
$$

$$
\begin{aligned}
\sum_{i=1}^n\sum_{j=1}^m \varphi(ij)&=\sum_{i=1}^n\sum_{j=1}^m \frac{\varphi(i)\varphi(j)\gcd(i,j)}{\varphi(\gcd(i,j))}\\
&=\sum_{d=1}^{\min(n,m)} \frac{d}{\varphi(d)}\sum_{i=1}^n\sum_{j=1}^m \varphi(i)\varphi(j)[\gcd(i,j)=d]\\
&=\sum_{d=1}^{\min(n,m)}\frac{d}{\varphi(d)} \sum_{i=1}^{\lfloor\frac{n}{d}\rfloor} \sum_{j=1}^{\lfloor\frac{m}{d}\rfloor} \varphi(id)\varphi(jd)[\gcd(i,j)=1]\\
&=\sum_{d=1}^{\min(n,m)}\frac{d}{\varphi(d)} \sum_{i=1}^{\lfloor \frac{n}{d}\rfloor} \sum_{j=1}^{\lfloor\frac{m}{d}\rfloor}\varphi(id)\varphi(jd)\sum_{k\mid i\or k\mid j} \mu(k)\\
&=\sum_{d=1}^{\min(n,m)}\frac{d}{\varphi(d)} \sum_{k=1}^{\lfloor\frac{\min(n,m)}{d}\rfloor}\sum_{i=1}^{\lfloor \frac{n}{dk}\rfloor}\sum_{j=1}^{\lfloor\frac{m}{dk}\rfloor} \varphi(idk)\varphi(jdk)\\
&=\sum_{k=1}^{\min(n,m)} \sum_{d|k}\mu(\frac{k}{d})\frac{d}{\varphi(d)}\sum_{i=1}^{\lfloor\frac{n}{k}\rfloor}\sum_{j=1}^{\lfloor\frac{m}{k}\rfloor} \varphi(ik)\varphi(jk)
\end{aligned}
$$

然后是神奇的预处理了，具体只能看题解了

```c++
bool npr[111111];
int pri[55555],mu[111111],phi[111111],cp;
int F[111111];
vector<int>G[100101],S[44][44];
inline void add(int &x,int y)
{
    x+=y;
    x>=mod?x-=mod:1;
}
void init()
{
    //vector<int>v(1000010);
    mu[1]=phi[1]=1;
    R(i,2,100000)
    {
        if(!npr[i]) pri[++cp]=i,mu[i]=-1,phi[i]=i-1;
        R(j,1,cp)
        {
            static int t;
            t=pri[j]*i;
            if(t>100000) break;
            npr[t]=1;
            if(i%pri[j]==0)
            {
                phi[t]=phi[i]*pri[j];
                break;
            }
            else
            {
                phi[t]=phi[i]*phi[pri[j]];
                mu[t]=-mu[i];
            }
        }
    }

    static int inv[111111];
    inv[1]=1;
    R(i,2,100000) inv[i]=(mod-mod/i)*inv[mod%i]%mod;
    R(i,1,100000) R(j,1,100000/i) add(F[i*j],(i*inv[phi[i]]%mod*(mu[j]%mod+mod)%mod)%mod);
    R(i,1,100000)
    {
        //test
        //G[i].resize(100000/i);
        G[i].resize(100000/i+5);
        //printf("%lld\n",(int)G[i].size());
        //test
        R(j,1,100000/i) G[i][j]=(G[i][j-1]+phi[i*j])%mod;
    }
    //test
    R(j,1,40) R(k,j,40)
    {
        S[j][k].resize(100000/k+5);
        R(i,1,100000/k) S[j][k][i]=(S[j][k][i-1]+F[i]*G[i][j]%mod*G[i][k]%mod)%mod;
    }
}
inline int calc(int n,int m)
{
    if(n>m) swap(n,m);
    int ans=0;
    R(i,1,m/40) add(ans,F[i]*G[i][n/i]%mod*G[i][m/i]%mod);
    for(int i=m/40+1,j=0;i<=n;i=j+1)
    {
        j=min(n/(n/i),m/(m/i));
        add(ans,(S[n/i][m/i][j]-S[n/i][m/i][i-1]+mod)%mod);
    }
    return ans;
}
signed main()
{
    init();
    for(int _=read();_--;)
    {
        int n=read(),m=read();
        writeln(calc(n,m));
    }
}
```



### 狄利克雷k次根加强版

#### 题意

给出一个函数$f:\{1,2,\cdots ,n\}\to \mathbb{Z}$，定义$(f*g)(n)=\sum\limits_{d\mid n}f(d)g(\frac{n}{d})$。

求一个$g:\{1,2,\cdots ,n\}\to \mathbb{Z}$使$g^k=f$。这里保证$f(1)=1$，所有运算在$\mathbb{F}_p$上进行，其中$p=998244353$。

$2\leq n\leq 10^6,1\le k<998244353$。

#### sol

$$
\ln F=\int \frac{F'}{F}
$$

$$
F'=F\ln n
$$

$$
\begin{alignat}{8} 
F^k &= G \\ 
kF^{k-1}\frac{G}{F} & =G'  \\ 
kF'\frac{G}{F} & = G' \\ 
F'G &=\frac{1}{k}G'\\
\sum_{d\mid n} f'(d)g\left(\frac{n}{d} \right)&=\frac{1}{k}\sum_{d\mid n} f(d)g'\left(\frac{n}{d} \right)\\
f'(n)g(1)+\sum_{d\mid n,d\neq n} f'(d)g\left(\frac{n}{d} \right)&=\frac{1}{k}\left(f(n)g'(1)+\sum_{d\mid n,d\ne n} f(d)g'\left(\frac{n}{d} \right) \right)
\end{alignat}
$$

$g(1)=1,g'(1)=0$。

