### 人类的本质

#### 题意

令
$$
f(n)=\sum_{1\le a_1,a_2,\cdots ,a_k\le n} \operatorname{lcm}(\gcd(a_1,n),\gcd(a_2,n),\cdots ,\gcd(a_k,n))
$$
求
$$
\sum_{i=1}^n f(i)\bmod 10^9+7
$$
$n\times k\le 10^9$。

#### sol

$$
\sum_{1\leq a_1,a_2,\cdots ,a_k\leq n} \operatorname{lcm}\left(\gcd(a_1,n),\gcd(a_2,n),\cdots,\gcd(a_k,n)\right)=\sum_{1\le a_1,a_2,\cdots ,a_k\le n}\frac{i}{\gcd\left(\left(\frac{i}{\gcd(i,a_1)},\frac{i}{\gcd(i,a_2)},\cdots ,\frac{i}{\gcd(i,a_k)} \right)\right)}
$$

然后令$b_j=\frac{i}{\gcd(i,a_j)}$，考虑对于每个$b_j$，有多少$a_j$满足$\frac{i}{\gcd(i,a_j)}=b_j$。
$$
\begin{array}{lcl} 
\frac{i}{\gcd(i,a_j)} & = & b_j \\ 
\gcd(i,a_j) & = & \frac{i}{b_j} \\
\gcd(\frac{a_jb_j}{i},b_j)&=&1
\end{array}
$$
因此共有$\varphi(b_j)$个$a_j$满足$\frac{i}{\gcd(i,a_j)}=b_j$。

然后原式变为：
$$
\sum_{i=1}^n \sum_{b_1,b_2,\cdots,b_k \mid i}\varphi(b_1)\varphi(b_2)\cdots \varphi(b_k)\frac{i}{\gcd(b_1,b_2,\cdots ,b_k)}
$$
然后令
$$
f(i)=\sum_{b_1,b_2,\cdots b_k\mid i}\varphi(b_1)\varphi(b_2)\cdots \varphi(b_k)\frac{i}{\gcd(b_1,b_2,\cdots ,b_k)}
$$
可以发现$f(i)$为积性函数。

证明：
$$
\begin{aligned}
f(i)f(j)&=\sum_{a_1,a_2,\cdots ,a_k\mid i} \varphi(a_1)\varphi(a_2)\cdots \varphi(a_k)\frac{i}{\gcd(a_1,a_2,\cdots,a_k)} \sum_{b_1,b_2,\cdots ,b_k\mid j} \varphi(b_1)\varphi(b_2)\cdots \varphi(b_k)\frac{j}{\gcd(b_1,b_2,\cdots,b_k)}\\
&=\sum_{a_1,a_2,\cdots ,a_k\mid i} \sum_{b_1,b_2,\cdots ,b_k\mid j} \varphi(a_1)\varphi(a_2)\cdots \varphi(a_k)\frac{i}{\gcd(a_1,a_2,\cdots,a_k)} \varphi(b_1)\varphi(b_2)\cdots \varphi(b_k)\frac{j}{\gcd(b_1,b_2,\cdots,b_k)}\\
&=\sum_{a_1b_1,a_2b_2,\cdots ,a_kb_k\mid ij} \varphi(a_1b_1)\varphi(a_2b_2)\cdots \varphi(a_kb_k)\frac{ij}{\gcd(a_1b_1,a_2b_2,\cdots ,a_kb_k)}\\
&=f(ij)
\end{aligned}
$$
考虑当$n=p^c$时$f(n)$的值，此时

{% raw %}
$$
f(p^c)=p^c\cdot \sum_{0\leq a_1,a_2,\cdots,a_k\leq c}\frac{\varphi(p^{a_1})\varphi(p^{a_2})\cdots\varphi(p^{a_k})}{p^{\min\{a_1,a_2,\cdots ,a_k\}}}
$$
{% endraw %}

令$m=\min\{a_1,a_2,\cdots ,a_k\}$
$$
\begin{aligned}
\sum_{\min\{a_1,a_2,\cdots,a_k\}=m} \varphi(p^{a_1})\varphi(p^{a_2})\cdots\varphi(p^{a_k})&=
\sum_{m\leq \min\{a_1,a_2,\cdots,a_k\}\le c} \varphi(p^{a_1})\varphi(p^{a_2})\cdots\varphi(p^{a_k})-\sum_{m< \min\{a_1,a_2,\cdots,a_k\}\le c} \varphi(p^{a_1})\varphi(p^{a_2})\cdots\varphi(p^{a_k})\\
&=\prod_{i=1}^k\sum_{m\leq j\leq c} \varphi(p^j)-\prod_{i=1}^k \sum_{m<j\le c} \varphi(p^j)\\
&=
\begin{cases}
p^{ck}-\left(p^{c-1} \right)^k & m=0\\
\left(p^c-p^{m-1} \right)^k-\left(p^c-p^{m} \right)^k & 0<m\leq c
\end{cases}
\end{aligned}
$$
因此若$m=0$，则$f(p^c)$的答案贡献为$p^c\left(p^{ck}-(p^c-1)^k\right)$，若$m\ge 1$，对答案的贡献为$p^{c-m}\left((p^c-p^{m-1})^k-(p^c-p^m)^k \right)$。

因此
$$
f(p^c)=p^c\left(p^{ck}-\left(p^c-1\right)^k \right)+\sum_{m=1}^c p^{c-m}\left(\left(p^c-p^{m-1} \right)^k-\left(p^c-p^m \right)^k \right)
$$
代入$c=1$，可以得到
$$
f(p)=p\cdot \left(p^k-(p-1)^k \right)+1\cdot \left((p-1)^k-(p-p)^k \right)=p^{k+1}-(p-1)^{k+1}
$$
同理可以得到：
$$
f(p^{c+1})=p^mf(p^c)+(p-1)p^c\cdot \left(p^{(c+1)k}-\left(p^{c+1}-1 \right)^k \right)
$$


（

而此时
$$
\begin{aligned}
f(p^c)&=\sum_{a_1,a_2,\cdots ,a_k\mid p^c}\varphi(a_1)\varphi(a_2)\cdots \varphi(a_k)\frac{p^c}{\gcd(a_1,a_2,\cdots,a_k)} \\ 
&=\sum_{0\le a_1,a_2,\cdots ,a_k\le c} \varphi(p^{c-a_1})\varphi(p^{c-a_2})\cdots \varphi(p^{c-a_k})\cdot p^{\max(a_1,a_2,\cdots ,a_k)}\\
&= \sum_{i=1}^c\left(g(i)-g(i-1) \right)  p^{i}
\end{aligned}
$$
其中$g(i)$表示$\max(x_1,x_2,\cdots,x_k)$小于等于$i$的方案数。

有：
$$
g(i)=
\begin{cases} 
p^{ck}, & \mbox{if }i=c \\
\left(p^c -p^{c-i-1} \right)^k, & \mbox{otherwise} 
\end{cases}
$$

$$
\begin{aligned}
f(p^{c+1})&=p^kf(p^c)-p^c\left(p^{(c+1)k}-\left(p^{c+1}-1 \right)^k \right)+p^{c+1}\left(p^{(c+1)k} -\left(p^{c+1}-1 \right)^k\right)\\
&=p^kf(p^c)+p^c(p-1)\left(p^{(c+1)k}-\left(p^{c+1}-1 \right)^k \right)
\end{aligned}
$$

）

然后就可以$O(n)$递推。

可以通过$n\le 10^7$的数据。


$$
\begin{aligned}
f(p)&=g(0)+pg(1)-pg(0)\\
&=(1-p)(p-1)^{k+1}-p^{k+1}\\
&=p^{k+1}-(p-1)^{k+1}
\end{aligned}
$$
将$(p-1)^{k+1}$展开，得到
$$
\begin{aligned}
f(p)&=p^{k+1}-\sum_{i=0}^{k+1}(-1)^{k-i+1} \binom{k+1}{i}p^i\\
&=-\sum_{i=0}^{k} (-1)^{k-i+1} \binom{k+1}{i} p^i\\
&=\sum_{i=0}^k (-1)^{k-i}\binom{k+1}{i}p^i
\end{aligned}
$$
因此$f(p)$就可以拆成$k+1$个完全积性函数的和。因此可以使用MIN-25筛来做，然后中间需要求自然数幂和，可以通过Bernoulli 数/Lagrange 插值*等方法完成。

