## CRT

对若干互质整数解线性同余方程组：
$$
\begin{cases} x&\equiv a_1 \pmod {n_1} \\ x&\equiv a_2 \pmod {n_2} \\ \cdots \\ x&\equiv a_k \pmod {n_k} \end{cases}
$$
其中$n_1,n_2,\cdots ,n_k$两两互质。

可以证明解在$0\sim \left(\prod\limits_{i} n_i \right)-1$范围内存在且唯一。

第一个不好证明来证一下第二个：

假设存在两个解$x_1,x_2\in [0,\prod_i n_i)$

那么显然有$x_1-x_2\equiv 0\pmod {n_i}$

因此$x_1-x_2\equiv 0\pmod {\prod_i n_i}$

所以$x_1=x_2$



尝试构造一个特解：$x_0=\sum\limits_{i=1}^k a_i\cdot e_i\cdot \operatorname{inv}(e_i,n_i)\bmod \left({\prod\limits_{i} n_i}\right)$，其中$e_i=\prod\limits_{i\neq j} n_j\bmod \left(\prod\limits_{i} n_i \right)$。



所有解形如$x_0+c\cdot \prod\limits_{i=1}^n n_i (c\in\mathbb{Z})$。（所以$x\equiv x_0\pmod {\prod_i n_i}$

需要使用扩展欧几里得算法求逆元。



## exCRT

当$n_i$不满足两两互质的性质时，此时同余方程组不一定有解，刚刚的构造算法就失效了。

为了解决一般化的问题，我们需要新的思路。

首先还是研究解的性质。令$M=\operatorname{lcm}(n_1,n_2,\cdots ,n_k)$。如果有解的话，我们取一个在$0\sim M-1$间的特解$x_0$，显然所有解均为$x_0+cM(c\in Z)$的形式。

那么我们可以发现，我们的解同样可以写成$x\equiv x_0\pmod M$的形式，这同样是一个同余方程。这样，我们可以考虑每次选择两个同余方程合并，得到一个新的同余方程，合并完所有的方程后就找到了最后的解，问题关键在于如何合并两个同余方程。

具体来说，我们要合并这样的两个同余方程：
$$
\begin{cases}x&\equiv a_1\pmod {n_1}\\x&\equiv a_2 \pmod{n_2} \end{cases}
$$
一个思路是我们令$x=n_1\cdot y_1+a_1=n_2\cdot y_2+a_2$，这样我们就可以得到一个不定方程$n_1\cdot y_1+a_1=n_2\cdot y_2+a_2$了。

令$d=\gcd(n_1,n_2)$，若$a_1\not\equiv a_2\pmod{d}$，则方程组显然无解。否则我们两边同时除$d$，得到$n_1'\cdot y_1+a_1'=n_2'\cdot y_2+a_2'$。因为此时$\gcd(n_1',n_2')=1$，那么可以直接解出$y_1\equiv(a_2'-a_1')\cdot \operatorname{inv}(n_1',n_2')\pmod {n_2'}$了。

回代得到$x\equiv n_1\cdot y_1+a_1\pmod {\operatorname{lcm}(n_1,n_2)}$。

（
$$
n_1'y_1= n_2'y_2+(a_2'+a_1')\\y_1\equiv (a_2'-a_1')\cdot\operatorname{inv}(n_1',n_2')\pmod {n_2'}
$$

）

同样需要用扩展欧几里得算法求逆元。

## [NOI2018] 屠龙勇士

### sol

其实就是给了一堆
$$
x\cdot ATK_i\equiv a_i \pmod {p_i}
$$
但这不是一个标准的同余方程，所以要把它先转成一个标准的形式。

具体就省略了

```c++
int n,m;
int a[111111],p[111111];
int f[111111],b[111111];
int v[111111];
int M,ans;

multiset<int>st;
inline void add(int &x,int y,int p=mod){x+=y,x>=p?x-=p:1;}
int gcd(int a,int b){return !b?a:gcd(b,a%b);}
int exgcd(int a,int b,int &x,int &y)
{
    if(!b) {x=1;y=0;return a;}
    int ret=exgcd(b,a%b,y,x);
    y-=x*(a/b);
    return ret;
}
inline int ginv(int n,int p)
{
    static int x,y,ret;
    ret=exgcd(n,p,x,y);
    if(ret<=1) return (x+p)%p;
    return -1;
}
inline int smul(int x,int y,int p)
{
    x=(x%p+p)%p,y=(y%p+p)%p;
    int ret=0;
    while(y)
    {
        if(y&1) add(ret,x,p);
        add(x,x,p);
        y>>=1;
    }
    return ret;
}
inline int excrt()
{
    M=p[1];ans=b[1];
    int x,y;
    R(i,2,n)
    {
        int A=M,B=p[i],C=(b[i]-ans%B+B)%B,D=exgcd(A,B,x,y),BG=B/D;
        if(C%D) return -1;
        x=smul(x,C/D,BG);
        ans+=x*M;
        M*=BG;
        ans=(ans%M+M)%M;
    }
    return 1;
}
void solve()
{
    st.clear();
    n=read(),m=read();
    R(i,1,n) a[i]=read();
    R(i,1,n) p[i]=read();
    R(i,1,n) f[i]=read();
    R(i,1,m) st.insert(read());
    R(i,1,n) 
    {
        auto it=st.begin();
        if((*it)<a[i]) it=--st.upper_bound(a[i]);
        v[i]=*it;st.erase(it);
        st.insert(f[i]);
    }
    int g,iv;
    R(i,1,n)
    {
        g=gcd(a[i],gcd(v[i],p[i]));
        a[i]/=g,v[i]/=g,p[i]/=g;
        iv=ginv(v[i],p[i]);
        if(!~iv) {puts("-1");return;}
        b[i]=smul(a[i],iv,p[i]);
        //printf("a:%lld b:%lld v:%lld p:%lld\n",a[i],b[i],v[i],p[i]);
    }
    if(!~excrt()) {puts("-1");return;}
	//x=ans(mod M)
    R(i,1,n)
    {
        int vl=(a[i]+v[i]-1)/v[i];
        if(vl<=ans) continue;
        int k=(vl-ans+M-1)/M;
        ans+=k*M;
    }
    writeln(ans);
}
signed main()
{
    for(int _=read();_--;) solve();
}
```

考虑将所有所有修改和询问离线下来，并且将队列编号看成时刻。这样就可以将操作一二的修改拆开，变成在$L_i$时刻加入数据结构，在$R_i+1$时刻弹出数据结构。

考虑使用一棵普通的线段树维护，下标为操作的顺序（因为操作也是有顺序的），每个节点维护当前区间元素的个数（可以是负数），区间最大元素子段和，区间**加入**元素的个数。

然后修改就单点修改，查询的时候线段树上二分即可。

```c++
int n,m,q;
int opt[255555],L[255555],R[255555],C[255555],K[255555];
struct seg
{
    int v,l,s;
    inline seg(int V=0,int L=0,int S=0): v(V),l(L),s(S) {}
    inline void upd(const seg &A){v+=A.v;l=max(l+A.v,A.l);s+=A.s;}
}t[1111111];
int ans[255555];
vector<pair<seg,int>>md[255555];
vector<pii>qu[255555];
inline seg upd(const seg &A,const seg &B)
{
    return seg(A.v+B.v,max(A.l+B.v,B.l),A.s+B.s);
}
inline void push_up(int x)
{
    t[x]=upd(t[x<<1],t[x<<1|1]);
}
void modify(int p,int l,int r,int x,const seg &k)
{
    if(l==r) {t[x]=k;return;}
    int mid=(l+r)>>1;
    if(p<=mid) modify(p,l,mid,x<<1,k);
    else modify(p,mid+1,r,x<<1|1,k);
    push_up(x);
}
void query(int p,int l,int r,int x,seg &sum)
{
    if(l==r) 
    {
        sum.upd(t[x]);
        return;
    }
    int mid=(l+r)>>1;
    if(p<=mid) query(p,l,mid,x<<1,sum);
    else sum.upd(t[x<<1]),query(p,mid+1,r,x<<1|1,sum);
}
int query_k(int l,int r,int x,int k)
{
    if(l==r) return l;
    int mid=(l+r)>>1;
    if(t[x<<1].s>=k) return query_k(l,mid,x<<1,k);
    else return query_k(mid+1,r,x<<1|1,k-t[x<<1].s);
}
signed main()
{
    ios::sync_with_stdio(0);
    cin.tie(0);
    cin>>n>>m>>q;
    R(i,1,q)
    {
        cin>>opt[i];
        if(opt[i]==1)
        {
            cin>>L[i]>>R[i]>>C[i]>>K[i];
            md[L[i]].pb(mkp(seg(K[i],K[i],K[i]),i));
            md[R[i]+1].pb(mkp(seg(0,0,0),i));
        }
        if(opt[i]==2)
        {
            cin>>L[i]>>R[i]>>K[i];
            md[L[i]].pb(mkp(seg(-K[i],0,0),i));
            md[R[i]+1].pb(mkp(seg(0,0,0),i));
        }
        if(opt[i]==3)
        {
            cin>>L[i]>>R[i];    
            qu[L[i]].pb(mkp(R[i],i));
        }
    }
    R(t,1,n)
    {
        for(const auto &qwq:md[t]) modify(qwq.se,1,q,1,qwq.fi);
        for(const auto &qwq:qu[t])
        {
            seg sum;
            query(qwq.se,1,q,1,sum);
            //printf("v:%lld l:%lld\n",sum.v,sum.l);
            ckmax(sum.v,sum.l);
            if(sum.v>=qwq.fi)
            {
                int k=sum.s-sum.v+qwq.fi;
                //printf("s:%lld v:%lld\n",sum.s,sum.v);
                ans[qwq.se]=C[query_k(1,q,1,k)];
            }
        }
    }
    R(i,1,q) if(opt[i]==3) cout<<ans[i]<<'\n';
}

```

## CF838D

### 题意

有$n$个位置排成一排，有$m$个人依次进场选位置，每个人一开始会选择一个方向，从左到右或从右向左，并选择一个位置，然后按他选择的方向入场并走到这个位置，从这个位置开始继续按他选择的方向走，直到遇到一个空位并坐下。如果一直找不到空位，他就会生气。求有多少种情况没有人生气。

$1\leq m\leq n\leq 10^6$。



### solution

看成一个长度为$n+1$环，其中编号$n+1$的点为间隔点（不能被占据），每次每个人可以选一个起点要么逆时针要么顺时针走到第一个空位上。如果编号为$n+1$的点被人占据了显然不合法，否则肯定合法。

由于这是一个环，因此最终每个点没被占据的概率是相同的。即一个点被占据的概率是$1-\frac{m}{n+1}$，乘以方案数$2^m (n+1)^m$即可。



## CTSC2017 吉夫特

### 题意

给定一个长度为$n$的数列$a_i$，求有多少个长度$\ge 2$的不上升子序列$a_{b_1},a_{b_2},\cdots ,a_{b_k}$满足

{% raw %}
$$
\prod_{i=2}^k \binom {a_{b_{i-1}}} {a_{b_{i}} } > 0 \pmod 2
$$
{% endraw %}

$1\leq n\leq 211985,1\leq a_i \leq 233333$，所有$a_i$互不相同。

答案对$10^9+7$取模。



### solution

显然根据 Lucas 定理，后一个$a_i$的二进制位应是前一个的超集。

令$f_i$表示以$a_i$结尾的答案，暴力的话就枚举前面所有$a_i$的子集转移即可。

考虑经典的优化，设$g_{x,y}$表示前$9$位恰好为$x$，后$9$位是$y$的子集的所有$a_j$对应$f_j$的和，那么我们每次转移只需要枚举$a_i$的前$9$位的子集即可。更新只需要枚举$a_i$后$9$位的超集。

```c++
int a[222222];
int n;
const int B=1<<9;
const int S=B-1;
int g[555][555];
inline void add(int &x,int y){x+=y;x>=mod?x-=mod:1;}
signed main()
{
    n=read();
    R(i,1,n) a[i]=read();
    int x,y,sum;
    R(i,1,n)
    {
        x=a[i]/B,y=a[i]%B,sum=0;
        for(int t=x^S;t;t=(t-1)&(x^S)) add(sum,g[t|x][y]);
        add(sum,g[x][y]);add(sum,1);
        for(int t=y;t;t=(t-1)&y) add(g[x][t],sum);add(g[x][0],sum); 
    }
    int ans=0;
    R(i,0,S) add(ans,g[i][0]);add(ans,mod-n);
    writeln(ans);
}
```



## Loj不等关系

### 题意

一个排列，相邻两个数有 `>` 或 `<` 的限制，求有多少种满足要求的排列。

$n\leq 10^5$。

### solution

令 `<` 为正向。

令$f(i,j)$表示前$i$个数，当前有$j$个数被划分为一组的概率。

如果$i-1$和$i$是 `<` ，那么$f(i,j)=\frac{f(i-1,j-1)}{j}$。

否则$f(i,1)=\sum f(i-1,j),f(i,j)=-\frac{f(i-1,j-1)}{j} (j>1)$。

最终答案自然就是$\sum f(n,j)$。

暴力$dp$是$O(n^2)$的，但是可以发现上面这个$dp$状态很“浪费”，相当于强行多加了一维状态让转移做到$O(1)$。

直接令$g(i)=\sum f(i,j)$（即只考虑前$i$个数的概率），考虑如何转移：

枚举上一次 `>` 被切断是什么时候，那么就有：

{% raw %}
$$
g(i)=\sum_{j=1}^{i-1} \frac{[s_j='>']}{(i-j)!} g(j)(-1)^{cnt_{i-1}-cnt_{j}}
$$
{% endraw %}

$cnt$为前缀大于号数量。

后面的式子显然是个卷积，因此可以分治NTT。

具体：

{% raw %}
$$
g(i)=(-1)^{cnt_{i-1}} \sum_{j=1}^{i-1} [s_j='>']g(j)(-1)^{cnt_j}\times \frac{1}{(i-j)!}
$$
{% endraw %}

（当然也可以求解微分方程然后 `exp`，但是并不一定跑得过分治NTT）

时间复杂度$O(n\log ^2 n)$。

```c++
const int _G=3;
const int invG=332748118;
char s[111111];
int n,m;
int cnt[444444];
int fac[444444],inv[444444],Finv[444444];
int G[444444];
int s1[444444],s2[444444],s3[444444];

inline void init_FAC(int lim)
{
    fac[0]=Finv[0]=inv[1]=1;
    R(i,2,lim) inv[i]=1ll*(mod-mod/i)*inv[mod%i]%mod;
    R(i,1,lim) fac[i]=1ll*fac[i-1]*i%mod,Finv[i]=1ll*Finv[i-1]*inv[i]%mod;
}
int tr[444444],tf;
inline void tpre(int n)
{
    if(tf==n) return;tf=n;
    R(i,0,n-1) tr[i]=(tr[i>>1]>>1)|((i&1)?n>>1:0);
}
void NTT(int *g,int rev,int n)
{
    tpre(n);
    static ull f[888888],w[888888];w[0]=1;
    R(i,0,n-1) f[i]=(((ll)mod<<5)+g[tr[i]])%mod;
    for(int l=1;l<n;l<<=1)
    {
        ull tG=fpow(rev?_G:invG,(mod-1)/(l+l));
        R(i,1,l-1) w[i]=w[i-1]*tG%mod;
        for(int k=0;k<n;k+=l+l)
        {
            R(p,0,l-1) 
            {
                int tt=w[p]*f[k|l|p]%mod;
                f[k|l|p]=f[k|p]+mod-tt;
                f[k|p]+=tt;
            }
        }
        if(l==(1<<10)) R(i,0,n-1) f[i]%=mod;
    }
    if(!rev) 
    {
        ull invn=fpow(n);
        R(i,0,n-1) g[i]=f[i]%mod*invn%mod;
    }
    else R(i,0,n-1) g[i]=f[i]%mod;
}
void px(int *f,int *g,int *p,int n) {R(i,0,n-1)p[i]=1ll*f[i]*g[i]%mod;}
inline int calc(int x){return x&1?1:998244352;}
void cdq(int l,int r)
{
    if(l==r) 
    {
        if(!l) G[l]=1;
        else G[l]=1ll*G[l]*calc(cnt[l]+1)%mod;
        return;
    }
    int mid=(l+r)>>1,l_n=r-l+1,lim=1;
    cdq(l,mid);
    for(;lim<=l_n;lim<<=1);
    clr(s1,lim+10),clr(s2,lim+10),clr(s3,lim+10);
    cpy(s2,Finv,lim+5);
    R(i,l,mid) s1[i-l]=1ll*G[i]*calc(cnt[i])%mod*(s[i]=='>');
    NTT(s1,1,lim),NTT(s2,1,lim);
    px(s1,s2,s3,lim);NTT(s3,0,lim);
    R(i,mid+1,r) G[i]=(G[i]+s3[i-l])%mod;
    cdq(mid+1,r);
}
signed main()
{
    ios::sync_with_stdio(0);
    cin.tie(0);
    cin>>(s+1);n=strlen(s+1)+1;s[0]=s[n]='>';
    init_FAC(400000);
    R(i,1,n) cnt[i]=cnt[i-1]+(s[i]=='>');
    cdq(0,n);
    cout<<1ll*fac[n]*G[n]%mod<<endl;
}
```



## Matrix-Tree 定理

Matrix-Tree 定理的本质是对环容斥。正常容斥系数应该是$(-1)^{环个数}$。

因为是无向图所以可以随便钦定一个点是根节点，因此基尔霍夫矩阵去掉某个对角线元素的所在的行列答案是一样的。而对于除了根以外的每个点都要钦定一条出边，这样总共钦定了$n-1$条边。要求它是一棵树的方案，就把它成环的方案减掉。最基本的想法就是容斥，容斥产生了多少个环，暴力的话就去枚举钦定产生了若干个环，剩下的点就钦定出来根之后任选出边，容斥系数为$(-1)^{环个数}$。

然后考虑行列式的定义，相当于任取一个排列出来，把排列全部乘起来再乘上$(-1)^{逆序对个数}$。一个定义是对于一个排列，每次交换任意两个数字，最后交换成$1,2,3,4,5,\ldots $奇排列经历的步数一定是奇数，偶排列定义的步数一定是偶数。而逆序对个数可以决定它是奇排列还是偶排列。

然后考虑一个排列会形成若干个置换环，然后考虑它要交换多少次才能回到初始的排列，答案即：n-环个数次。因为每个置换环都要交换环长-1次，所以要交换n-环个数次才能回到初始排列。因此最后的$(-1)$指数上逆序对个数也可以理解为n-环个数。

基尔霍夫矩阵对角线上全部是度数。

Matrix-Tree 定理删掉基尔霍夫矩阵中根所在的行列后，任意一个排列如果某一位选了它自己（即选在对角线上），那就说明从出边中随便选了一条；否则剩余的部分会形成若干个长度$> 1$的置换环（事实上这些就对应了原图的一个环（这是一个邻接矩阵）），如果这些环形成的是奇排列则会有$-1$的系数。

奇排列就相当于环的总长度减掉环个数是奇数，由于非对角线元素都取了相反数，因此$(-1)$被乘的次数恰好是环的总长度，再乘上奇排列的系数，恰好就是$(-1)^{环个数}$。

总结一下就是用行列式的定义：每次选择一个排列，这些排列与原图的选法一一对应，然后它乘的系数恰好就是$(-1)^{环个数}$。

因此 Matrix-Tree 定理不仅可以用于无向图，也很容易可以推广到任意有向图上。

关于 Matrix-Tree 定理在有向图上的一个例子：

![](https://files.catbox.moe/o883ah.png)

现在要求内向生成树个数。就可以将它的基尔霍夫矩阵写出来。（对角线上都是出度，因为是选内向生成树，每个点要钦定出边。）这里将根删掉了，因为无向图可以删掉对角线上点对应的行列是因为每个点都可以作为根，而有向图只能删掉根所在的行列。
$$
\begin{bmatrix} 2 & -1 & -1 \\ 0 & 1 & 0 \\ 0 & 0 & 1\end{bmatrix}
$$
最后只要算一下这个矩阵的行列式即可。



## LGV 引理

### 题意

一个 DAG ，给定$n$个起点$a_1,a_2,\cdots,a_n$和$n$个终点$b_1,b_2,\cdots ,b_n$，求选出$n$条路径$(a_1,b_1),\cdots,(a_n,b_n)$且这些路径互不相交（不经过同一个点多次）的方案。

$n\leq 500$

### solution

设$f(a,b)$表示$a\to b$的方案数，那么答案就是下面的行列式：
$$
\begin{bmatrix} f(a_1,b_1) & f(a_1,b_2) & \cdots &f(a_1,b_n) \\ f(a_2,b_1) & f(a_2,b_2) & \cdots & f(a_2,b_n) \\ \vdots & \vdots & \vdots &\vdots \\f(a_n,b_1)& f(a_n,b_2) &\cdots &f(a_n,b_n) \end{bmatrix}
$$
证明考虑如果最终路径产生了$k$个交点，那么可以决策这$k$个交点的两条出边分别交不交换，只要交换一次，最终的终点序列必然也会恰好交换一次，即改变排列的奇偶性。

因此若$k>0$，则最终能够交换得到的奇排列和偶排列的数量一样（可以一一对应）
当且仅当$k=0$（即不产生交点）的时候，会被统计进答案。



## 模板题

https://www.luogu.com.cn/problem/P6657

### 题意

$m$个棋子，初始分别在$(a_i,0)$，最终分别要走到$(b_i,n)$，每次只能向右向上走，求路径不交的方案数。

$m\leq 100,n\leq 10^6$。

### solution

由于每次只能向右向上走，因此是个 DAG ，直接应用 LGV 引理即可。

任意两点之间路径的方案数是个组合数，因此复杂度$O(n+m^3)$。



## 生成函数

### 基本操作

#### 多项式求逆

给出$P(x)$，要求$Q(x)$使得$P(x)Q(x)\equiv 1 \pmod {x^n}$。

假设已经求出了$P(x)H(x)\equiv 1\pmod {x^k}$现在求
{% raw %}
$P(x)Q(x)\equiv 1\pmod {x^{2k}}$
{% endraw %}


把$1$减到左边两边同时平方，得
{% raw %}
$P^2(x)H^2(x)+1-2P(x)H(x)\equiv 0\pmod {x^{2k}}$
{% endraw %}
，整理一下$Q(x)=2H(x)-P(x)H^2(x)$。

因此倍增即可，复杂度$O(n\log n)$。

#### 多项式$\ln$

注意到$\frac{d\ln F(x)}{dx}=\frac{F'(x)}{F(x)}$，因此做一次多项式求逆和多项式乘法，再积分即可。

复杂度$n\log n$。

#### 多项式$\exp$

给定$F(x)$，求$G(x)=e^{F(x)}$。

假设已知
{% raw %}
$P(x)=e^{F(x)} \pmod {x^k},G(x)=e^{F(x)}\pmod {x^{2k}}$
{% endraw %}
，则在$x_0=P(x)$处展开$\ln G(x)$，得：

{% raw %}
$$
\ln G(x)=F(x)\equiv \ln P(x)+\frac{1}{P(x)}\left(G(x)-P(x)\right) \pmod {x^{2k}}
$$
{% endraw %}

因此$G(x)=P(x)+\left(F(x)-\ln P(x)\right)P(x) \pmod {x^2k}$。

（这里使用泰勒展开而并不是牛顿迭代推导便于了解为什么牛顿迭代每次精度可以乘$2$）

因此也可以倍增，复杂度$O(n\log n)$但常数非常大。

以及还可以写更好写复杂度为$O(n\log^2 n)$的分治`FFT`，由于常数小所以并不会比牛顿迭代慢。

具体可以看这 https://www.cnblogs.com/hizeci/p/14886812.html#%E6%B1%82-1

#### 多项式除法

给定$A(x),B(x)$，求$P(x),Q(x)$满足$A(x)=B(x)P(x)+Q(x)$，其中$A,B$分别为$n,m$次多项式，$P,Q$分别为$n-m,m-1$次多项式

把左右两边的多项式同时反转系数（`reverse`），则：
$$
A(x)=B(x)P(x)+Q(x)x^{n-m+1}
$$
则两边同时对$x^{n-m+1}$取模后，多项式求逆即可解出$P(x)$。

则$Q(x)=A(x)-B(x)P(x)$。

时间复杂度$O(n\log n)$。

#### 多点求值

设要求$F(x)$在$x_1,x_2,\cdots x_k$的点值，则让$F(x)$对多项式$(x-x_1)\cdot(x-x_2)\cdot \ldots \cdot(x-x_k)$取模之后答案显然不变。

大概就是令$P(x)=(x-x_1)\cdot (x-x_k)\cdot \ldots \cdot (x-x_k)$。

$F(x)=P(x)R(x)+Q(x)$，$Q(x)$为取模后的结果。可以发现代入任意$x_1,\cdots ,x_k$，前面的$P(x)R(x)$等于$0$，所以说$F(x)$在$x_1,\cdots ,x_k$处的点值与$Q(x)$在$x_1,\cdots ,x_k$的点值一样。

因此分治，每次仅对要求值的部分取模，然后递归下去处理。

总复杂度$O(n \log^2 n)$

#### 快速插值

考虑拉格朗日插值的算式：
$$
F(x)=\sum y_i \prod_{i\neq j} \frac{x-x_j}{x_i-x_j}
$$
首先我们要对于每个$i$求出$\prod\limits_{i\neq j} (x_i-x_j)$，这等于如下极限：
$$
\lim_{x\to x_i} \frac{\prod_j (x-x_j)}{x-x_i} =\lim_{x\to x_i} \left(\prod_{j}(x-x_j) \right)'
$$
因此先算出括号内的多项式，求导后多点求值即可。

接下来要算类似于$\sum d_i \prod\limits_{j\neq i}(x-x_j)$的东西，直接分治`fft`即可。

总时间复杂度$O(n\log^2 n)$。但常数巨大。



## [HAOI2018]染色

### 题意

$n$个位置，$m$种颜色，给定正整数$s$，对于每个$0\leq k\leq m$求出恰有$k$种颜色恰好出现$s$次的方案数。

$n\leq 10^7,m\leq 10^5$

### sol

固定一个K,考虑如何求答案。
枚举至少有多少种颜色恰好出现了s次，进行容斥。
$$
\sum_{i=k}^m \frac{n!}{(S!)^i \times (n-iS)!}\binom m i (m-i)!^{n-iS}\times (-1)^{i-k}\binom i k
$$
过程：

考虑容斥，计算出恰好出现了$s$次的颜色至少有$i$种的方案数$f_i$，钦定$i$种颜色正好放$S$种

有$m$种颜色选$i$种,所以有一个$\binom m i$

然后这$n$个位置分成$i+1$个部分:被钦定的$i$中颜色，每个有$S$个；剩下的$m-i$种颜色，一共$n-i\times S$个

先看作是可重的全排列数，那么方案就有$\frac {n!}{(S!)^i\times(n-iS)!}$前面各部分都是只有一种颜色，后面部分有$m-i$种取法，所以还有一个$(m-i)^{n-iS}$.

综上$f_i=\frac{n!}{(S!)^i \times (n-iS)!}\binom m i (m-i)^{n-iS} $

$$
ans_k=\sum_{i=k}^{m}(-1)^{i-k}\times \binom i k\times f_i
$$

拆开得:

$$
ans_k=\sum\limits_{i=k}^{m} (-1)^{i-k}\times \frac{i!}{k!(i-k)!}\times f_i
$$

$$
ans_k\times k!=\sum\limits_{i=k}^{m}(-1)^{i-k}\times \frac{1}{(i-k)!}\times i!\times f_i
$$

设$A_i=i!\times f_i,B_i=\frac{(-1)^i}{i!}$

有$G_k=\frac{1}{k!}\sum\limits_{i=k}^{m}A[i]\times B[i-k]$

上式只与变量$i$与$i-k$有关，显然是卷积形式。复杂度$m \log m$

## 范德蒙行列式

当范德蒙行列式中$a_i\leq 10^6$时可以一次卷积求出行列式。但当$a_i\leq 10^9$时就不能这么做了。

注意到范德蒙矩阵的行列式为$\prod\limits_{i<j} (x_j-x_i)$，我们考虑取一个正负$1$的系数然后平方，让它变成：$\prod\limits_{i\neq j}(x_j-x_i)$。大概就是：

{% raw %}
$$
\left(\prod_{i<j} (a_j-a_i) \right)^2 \cdot (-1)^{\frac{n\cdot (n-1)}{2}}=\prod_{i\neq j} (a_j-a_i)
$$
{% endraw %}

这正是我们在快速插值的时候要求的东西。

因此范德蒙行列式可以$O(n\log^2 n)$求出。

首先可以发现一定有一个合法的排列为$p_i=i$，因此如果对于某个$i$出现了$x_i<i$，显然此时一定无解。此外还可以得出$b_i\ge a_i+t$。

考虑$x_i=c$代表什么，这意味着存在一个排列$p$，其中第$i$辆公交车的出现时刻为$b_c$，而此时$i+1\sim c$的公交车会去哪里？那么此时有一种贪心的构造方式：
$$
i\to c,i+1\to i,i+2\to i-1,\cdots,c\to c-1
$$
显然这已经是最优的了。

因此考虑初始化$b_i=a_i+t$。

然后扫一遍记录当前$mx=\max\{a_i \}$，若$mx>i$，则要$b_i=b_{i+1}$并且将$b_{i+1}$加$1$。

最后再判断一下每个数能否到达对应的$x_i$即可。

```
inline void evil(){puts("No");exit(0);}
int n,t;
int a[222222],x[222222];
int b[222222];
signed main()
{
    n=read(),t=read();
    R(i,1,n) a[i]=read();
    R(i,1,n) 
    {
        x[i]=read();
        if(x[i]<i) evil();
    }
    R(i,1,n) b[i]=a[i]+t;
    int mx=0;
    R(i,1,n) 
    {
        mx=max(mx,x[i]);
        if(mx>i) b[i]=b[i+1],++b[i+1];
    }
    for(int L=1,R=1;L<=n;L++)
    {
        if(R<=L) R=L+1;
        while(R<=n&&a[R]+t<=b[R-1]) ++R;
        if(x[L]!=R-1) evil();
    }
    puts("Yes");
    R(i,1,n) printf("%lld ",b[i]); puts("");
}

```

在树上$a,b$两点存在边当且仅当包含$b$的$a$集合大小与包含$a$的$b$集合大小之和为$n$。因此直接暴力找出所有的边然后一堆判断是否是一棵树即可。

稍微讲一下怎么判：

1. 首先边数不为$n-1$时显然不是一棵树。

2. `dfs`一遍判断这是否是一棵树，具体为看一个点是否被多次访问到以及最后根节点子树和应该为$n$
3. 最后暴力判断假设某个点为根，那么子树的情况是否与输入时相同。本人是直接每个点开了`vector<vector<int>>`记录子树内的情况，然后每次`sort`一遍方便判断两个集合是否相等。当然这也可以用`hash`做到。

```cpp
int n,m;
vector<vector<int>>t[1111];
vector<pii>ans;
vector<int>e[1111];
int cnt[1111][1111],cnte;
int vis[1111],siz[1111],fa[1111];
void dfs1(int u)
{
    siz[u]=1;
    vis[u]=1;
    for(int v:e[u]) if(v^fa[u])
    {
        if(vis[v]) evil();
        fa[v]=u;
        dfs1(v);
        siz[u]+=siz[v];
    }
}
void dfs2(int u,int f,vector<int>&chi)
{
    chi.pb(u);
    for(int v:e[u]) if(v^f) dfs2(v,u,chi); 
}
void check()
{
    R(u,1,n)
    {
        vector<vector<int>>all;
        for(int v:e[u])
        {
            all.pb(vector<int>());
            dfs2(v,u,all.back());
            sort(all.back().begin(),all.back().end());
        }
        sort(all.begin(),all.end());
        if(t[u]!=all) evil();
    }   
}
signed main()
{
    scanf("%d",&n);
    R(i,1,n)
    {
        int del=n-1;
        while(del)
        {
            t[i].pb(vector<int>());
            scanf("%d:",&m);
            int x;
            R(j,1,m)
            {
                scanf("%d",&x);
                t[i].back().pb(x);
                if(j+1<=m) scanf(",");
                cnt[i][x]=m;
            }
            sort(t[i].back().begin(),t[i].back().end());
            del-=m;
            if(del) scanf("-");
        }
        sort(t[i].begin(),t[i].end());
    }
    R(u,1,n) R(v,u+1,n) if(cnt[u][v]+cnt[v][u]==n) e[u].pb(v),e[v].pb(u),++cnte,ans.pb(mkp(u,v));
    if(cnte^(n-1)) evil();
    dfs1(1);
    if(siz[1]^n) evil();
    check();
    writeln((int)ans.size());
    for(auto v:ans) writesp(v.fi),writeln(v.se);
}

```

首先考虑$\forall i,b_i=M(1\leq i\leq n)$这种特殊的情况，显然当且仅当$M=0$时有解，证明可以考虑因为是一个环，所以总会存在一个$a_{i\bmod n}=kM,a_{(i \bmod n)+1}=M(1\leq i < n)$此时$b_i=0$。

令$M=\max\limits_{i=1}^n b_i$，然后找到一个下标$i(1\leq i\leq n)$满足$b_{(i-1) \bmod n}<M$且$b_{i\bmod n}=M$（这里认为$b_0=b_n$）。假设这个下标是$n$，如果不是可以则通过平移数组平移到$n$。

然后考虑构造$a$数组：

$$

a_i=\begin{cases} \sum_\limits{j=i}^{n-1}b_j+2b_n & i<n \\ b_n  & i=n \end{cases}

$$

这样的$a$数组满足所有条件。因为：

- $a_n<a_1$
- $a_i-a_{i+1}=b_i(i<n)$
- $b_{i}<a_{i+1}(i<n-1)$因为$b_n$是最大的数，且$b_n>0$
- $b_{n-1}<b_n=M$
- $b_n<a_1$因为$b_n<2b_n$

以及，如果数组中除了$1$都是$0$，那么$b_n$前面的系数$2$并没有什么作用，因为此时$a_n \bmod a_1=0$。以及事实上可以用$b_n+10^{10}$代替$2b_n$，显然此时构造方法仍然成立。

```cpp
int n;
int a[155555],b[155555];
int mxv,mxp=-1;
inline int tp(int x)
{
    if(!x) return n;
    return x;
}
signed main()
{
    n=read();
    R(i,1,n) a[i]=b[i]=read();a[0]=b[0]=b[n];
    mxv=*max_element(b+1,b+n+1);
    R(i,1,n) if(b[i]==mxv&&b[i-1]^mxv) {mxp=i;break;}
    if(!~mxp)
    {
        if(!mxv) 
        {
            puts("YES");
            R(i,1,n) writesp(1);puts("");
        }
        else puts("NO");
        return 0;
    }
    a[tp((mxp-1+n)%n)]+=mxv;
    R(i,1,n-1) a[tp((mxp-i+n)%n)]+=a[tp((mxp-i+1+n)%n)];
    puts("YES");
    R(i,1,n) writesp(a[i]);puts("");
}
```

## CF533D Landmarks

### solution

只考虑最后剩下来的柱子，假设柱子$i$两边分别为柱子$j$和柱子$k$，需要满足$d_i\ge \frac{x_k+x_j}{2}$。考虑在不加仍何柱子的情况下，如何判断会不会塌。

设$dp_i$表示考虑前$i$个柱子，在第$i$个柱子选做最后保留的柱子的情况下，前一个选中的柱子在哪里。转移大概是$dp_i =\max\limits_{2\times d_j +dp_j\ge x_i} x_j$，（第$j$根柱子合法需要满足，需要满足$d_j\ge \frac{x_i-dp_j}{2}$），直接单调栈维护即可。

接着考虑加入一根柱子怎么做，考虑先正着反着$dp$一下。然后考虑计算出每根柱子在两个方向剩下来的能支撑的长度，设其为$v1_i$和$v2_i$。

就比如当前柱子为$i$，前面最近的柱子为$j$，那么$v1_i$就是下一根柱子最远距离是多少，大概就是$2d_i-(x_i-x_j)$。反向同理设为$v2_i$。

考虑枚举加的柱子，如果左边选了$i$，右边选了$j$，所需要的$d$为$\frac{x_j-x_i}{2}$，需要满足的条件为$v1_i,v2_j>0,v1_i+v2_j \ge \frac{x_j-x_i}{2}$，最后求出最小的$\frac{x_j-x_i}{2}$，这个也可以使用单调栈维护，具体就是这个可以化为$2v1_i+x_i\ge x_j-2v2_j$。然后枚举一维就可以了。

```c++
int n;
int x[111111],d[111111];
int stk[111111],top;
int L[111111],R[111111];
inline int check(int r,int v)
{
    int l=0;
    while(r-l>=10)
    {
        int mid=(l+r)>>1;
        if(2*d[stk[mid]]+L[stk[mid]]>=v) l=mid+1;
        else r=mid-1;
    }
    L(i,l,r) if(2*d[stk[i]]+L[stk[i]]>=v) return i;
}
signed main()
{
    n=read();
    R(i,0,n+1) x[i]=read();
    R(i,1,n) d[i]=read();
    d[0]=d[n+1]=inf;
    R(i,1,n+1)
    {
        while(top&&2*d[stk[top]]+L[stk[top]]<x[i]) --top;
        L[i]=x[stk[top]];
        stk[++top]=i;
    }
    if(top>1) return puts("0")&0;
    stk[top=0]=n+1;
    L(i,1,n)
    {
        while(top&&R[stk[top]]-2*d[stk[top]]>x[i]) --top;
        R[i]=x[stk[top]];
        stk[++top]=i;
    }
    stk[top=0]=0;
    int ans=1e10;
    R(i,1,n+1)
    {
        if(x[i]>R[i]-2*d[i])
        {
            int j=check(top,R[i]-2*d[i]);
            assert(i>=stk[j]);
            ckmin(ans,x[i]-x[stk[j]]);
        }
        if(x[i]>=2*d[i]+L[i]) continue;
        while(top&&2*d[i]+L[i]>=2*d[stk[top]]+L[stk[top]]) --top;
        stk[++top]=i;
    }
    printf("%.12lf\n",ans/2.0);
}   

```



## 「2018 集训队互测 Day 1」完美的队列

### solution

考虑对于每一次操作求出最早在什么时候所有在这次操作被加的数会被全部弹出，设其为$f_i$。

考虑如何求出$f_i$，首先将$a$序列分块，对于每一个块分开处理。那么$f_i=\max$(两边的贡献，中间整块的贡献)。

考虑对于一个操作怎么求整块的贡献，要么是直接覆盖了整块，要么是中间一部分或者前缀后缀，对操作`two-pointers`扫一下（因为越早加入一定越早删除），从小往大枚举区间$l$，然后维护$r$表示第$l$次操作加入的数在$r$次操作时全部被删除，显然随着$l$增加，$r$也一定增加。所以需要维护整体加、前缀后缀加、求有没有大于$0$的元素。整体加直接打一个$tag$即可，前缀后缀加的总操作数最多只有$2m$次，于是直接暴力重构即可。

然后考虑对于两边的点怎么求贡献，考虑对于这每个点维护一个`vector`，表示包含这个点但不包含整个区间的操作。显然对于所有这样的点，`vector`的`size`总和不超过$m\sqrt n$。对于一个点来说，有些操作是加入一个点，有些操作是加入一整个块。那么类似于整块，考虑同样对于操作`two-pointers`扫一下，对于某个操作$l$，去找到某一个操作$r$，表示最早什么时候被删除。由于这个$r$有可能是`vector`中的一个点，也有可能是某个大块，所以先预处理出$pre_i$表示前$i$个操作中有多少整块操作，再维护一个$id_i$表示第$i$块操作的$id$是多少，然后先再`vector`上`two-pointers`扫一下具体在哪两个相邻的点操作之间，然后可能两个点间有若干个块操作，再找一下具体是哪个。

```c++
const int B=333;
int n,m;
int a[111111],b[111111];
pii c[111111];
int l[111111],r[111111];
vector<int>col[111111];
vector<int>v[1111];
int cnt,id[111111],pre[111111];
int lp,rp,mx;
int tag,rr,lst;
int f[111111],ans[111111];

signed main()
{
    n=read(),m=read();
    R(i,1,n) a[i]=read();
    int x;
    R(i,1,m) l[i]=read(),r[i]=read(),x=read(),col[x].pb(i);

    for(int L=1,R;L<=n;L+=B)
    {
        R=min(n,L+B-1);

        mx=tag=rr=cnt=0;
        R(i,1,R-L+1) v[i].clear();

        R(i,1,m)
        {
            if(l[i]<=L&&R<=r[i])
            {
                ++cnt;
                id[cnt]=i;
            }
            else
            {
                lp=max(l[i],L),rp=min(r[i],R);
                R(j,lp,rp) v[j-L+1].pb(i);
            }
            pre[i]=cnt;
        }

        R(i,L,R) ckmax(mx,a[i]),b[i]=a[i];

        R(i,1,m) 
        {
            if(l[i]<=L&&R<=r[i]) tag--;
            else
            {
                lp=max(l[i],L),rp=min(r[i],R);
                if(lp<=rp)
                {
                    mx=-inf;
                    R(j,L,R) 
                    {
                        b[j]-=tag;
                        if(lp<=j&&j<=rp) ++b[j];
                        ckmax(mx,b[j]);
                    }
                    tag=0;
                }
            }
            while(rr<=m&&mx-tag>0)
            {
                ++rr;
                if(l[rr]<=L&&R<=r[rr]) ++tag;
                else
                {
                    lp=max(l[rr],L),rp=min(r[rr],R);
                    if(lp<=rp) 
                    {
                        mx=-inf;
                        R(j,L,R)
                        {
                            b[j]-=tag;
                            if(lp<=j&&j<=rp) --b[j];
                            ckmax(mx,b[j]);
                        }                    
                        tag=0;
                    }
                }
            }
            if(pre[i]-pre[i-1]) ckmax(f[i],rr-1);
        }

        R(i,1,R-L+1)
        {
            rr=1;lst=a[i+L-1];
            R(j,0,(int)v[i].size()-1)
            {
                while(rr<(int)v[i].size()&&rr-j+pre[v[i][rr]]-pre[v[i][j]]<=lst) ++rr;
                lp=lst-(rr-1-j)+pre[v[i][j]];
                if(lp>cnt) ckmax(f[v[i][j]],m);
                else ckmax(f[v[i][j]],max(id[lp],v[i][rr-1])-1);
            }
        }
    }
    R(i,1,100000) if((int)col[i].size()>0)
    {
        cnt=0;
        R(j,0,(int)col[i].size()-1)
        {
            c[++cnt]=mkp(col[i][j],1);
            c[++cnt]=mkp(f[col[i][j]]+1,-1);
            //printf("i:%d col:%d f:%d\n",i,col[i][j],f[col[i][j]]);
        }
        sort(c+1,c+cnt+1);
        int tag=0;
        R(i,1,cnt-1) 
        {
            tag+=c[i].se;
            if(tag>0) ++ans[c[i].fi],--ans[c[i+1].fi];
        }
    }
    R(i,1,m) ans[i]+=ans[i-1];
    R(i,1,m) writeln(ans[i]);
}
```





## 「ROI 2019 Day2」机器人高尔夫球赛

### solution

考虑当$(i,j),(i+1,j),(i+2,j),(i,j+1),(i,j+2),(i+1,j+1)$都为空时，
$$
g_{i,j}=\min\left(\max\left(g_{i+2,j},g_{i+1,j+1}\right),\max\left(g_{i,j+2},g_{i+1,j+1}\right)\right)=\max\left(g_{i+1,j+1},\min\left(g_{i+2,j},g_{i,j+2} \right)\right)
$$
因为
$$
g_{i+2,j}=\min\left(f_{i+3,j},f_{i+2,j+1} \right)
$$

$$
g_{i,j+2}=\min\left(f_{i,j+3},f_{i+1,j+2}\right)
$$

$$
g_{i+1,j+1}=\min\left(f_{i+2,j+1},f_{i+1,j+2} \right)
$$

所以
$$
\min\left(g_{i+2,j},g_{i,j+2}\right)=\min\left(f_{i+3,j},f_{i,j+3},g_{i+1,j+1} \right)
$$
所以
$$
g_{i+1,j+1}\ge \min(g_{i+2,j},g_{i,j+2})
$$
所以
$$
g_{i,j}=g_{i+1,j+1}
$$
于是关键点只有$6\times 10^5$个，直接$\text{dp}$即可。

```c++
const int hs=1235287;
int dp[666666][2];
int n,m,k;
vector<pii>all;
map<pii,int>mp;
vector<int>v[666666];

struct hashtable
{
    int head[hs+10],cnt;
    struct edge
    {
        int nxt,key,val;
    }e[666666];
    inline int hash(int x){return (x%hs+hs)%hs;}
    inline void add_edge(int u,int v,int d){e[++cnt]=(edge){head[u],v,d};head[u]=cnt;}
    inline int find(int x)
    {
        static int h;
        h=hash(x);
        for(int i=head[h];i;i=e[i].nxt) if(e[i].key==x) return i;
        return 0;
    }
    inline void ins(int x)
    {
        static int h;
        h=hash(x);
        for(int i=head[h];i;i=e[i].nxt) if(e[i].key==x) return;
        add_edge(h,x,x);
    }
}ht;
int f(int x,int y,int opt)
{
    int s=ht.find(x-y);
    if(!s) return 0;
    int t=lower_bound(v[s].begin(),v[s].end(),x)-v[s].begin();
    if(t==(int)v[s].size()) return 0;
    return dp[lower_bound(all.begin(),all.end(),mkp(v[s][t],v[s][t]-x+y))-all.begin()][opt];
}
signed main()
{
   // freopen("78.in","r",stdin);
    n=read(),m=read(),k=read();
    int x,y,z;
    R(i,1,k) 
    {
        x=read(),y=read(),z=read();
        all.pb(mkp(x,y));
        mp[mkp(x,y)]=z;
        if(x>1) all.pb(mkp(x-1,y));
        if(y>1) all.pb(mkp(x,y-1));
        if(x>2) all.pb(mkp(x-2,y));
        if(y>2) all.pb(mkp(x,y-2));
        if(x>1&&y>1) all.pb(mkp(x-1,y-1)); 
    }
    sort(all.begin(),all.end());
    all.resize(unique(all.begin(),all.end())-all.begin());
    for(pii qwq:all) 
    {
        x=qwq.fi,y=qwq.se;
        ht.ins(x-y);
        v[ht.find(x-y)].pb(x);
    }
    L(i,0,(int)all.size()-1)
    {
        x=all[i].fi,y=all[i].se;
        if(mp.find(mkp(x,y))!=mp.end()) 
        {
            dp[i][0]=dp[i][1]=mp[mkp(x,y)];
            continue;
        }
        dp[i][0]=min(f(x+1,y,1),f(x,y+1,1));
        dp[i][1]=max(f(x+1,y,0),f(x,y+1,0));
    }
    int ans=0;
    int pre;
    R(i,1,ht.cnt)
    {
        if(ht.e[i].val>0) pre=ht.e[i].val;  
        else pre=0;
        R(j,0,(int)v[i].size()-1)
        {
            ans=(ans+1ll*(v[i][j]-pre)*dp[lower_bound(all.begin(),all.end(),mkp(v[i][j],v[i][j]-ht.e[i].val))-all.begin()][0])%mod;
            pre=v[i][j];
        }
    }
    writeln((ans%mod+mod)%mod);
}
```



## CF708D 



### solution

考虑先假设按照原来的方案，将入度大的点和出度大的点分开。对于入度大的点，假设入度多$in[i]$，那么加入边$(s,i,in[i],0)$。对于出度大的点，假设出度多$out[i]$，那么加入边$(i,t,out[i],0)$。

假设有一条边$(a,b,c,f)$。若$f\leq c$，则加入边$(a,b,c-f,1),(a,b,\infty,2),(b,a,f,1)$，然后三个意思分别是只修改$f$，费用是$1$；或者同时改变$c,f$费用是$2$；或者将$f$减小，费用也是$1$。若$f>c$，则先给答案加$f-c$（将$f$改成$c$），再加入边$(x,y,\infty,2),(y,x,f-c,0),(y,x,c,1)$。

最后考虑$1$号点和$n$号点不需要出入平衡，设所以$in[i]$的和为$sum$，故加入边$(s,1,\infty-sum,0),(n,t,inf-sum), (1,n,\infty,0)$。最后跑MCMF即可。

```c++
int n,m;
int s,t;
struct edge
{
    int nxt,to,cap,cst;
}e[2222];
int head[111],cnt=1;
int ind[111],oud[111];
int dis[111],h[111],vis[111];
int flow[2222];
int ans;

inline void add_edge(int u,int v,int f,int c)
{
    e[++cnt]=(edge){head[u],v,f,c};head[u]=cnt;
}
inline void link(int u,int v,int f,int c)
{
    add_edge(u,v,f,c),add_edge(v,u,0,-c);
}
void spfa()
{
    deque<int>q;
    R(i,1,t) h[i]=inf;
    h[s]=0,vis[s]=1;
    q.pb(s);
    int u,v;
    while((int)q.size()>0)
    {
        u=q.front();q.pop_front();
        vis[u]=0;
        for(int i=head[u];i;i=e[i].nxt)
        {
            v=e[i].to;
            if(e[i].cap&&h[v]>h[u]+e[i].cst)
            {
                h[v]=h[u]+e[i].cst;
                if(!vis[v]) vis[v]=1,q.pb(v);
            }
        }
    }
}
struct node
{
    int val,pos;
    inline int operator <(const node &A)const {
        return val>A.val;
    }
};
pii p[111];
int dij()
{
    priority_queue<node>q;
    R(i,1,t) dis[i]=inf,vis[i]=0;
    dis[s]=0;
    q.push((node){dis[s],s});
    int u,v,tc;
    while((int)q.size()>0)
    {
        u=q.top().pos;q.pop();
        if(vis[u]) continue;vis[u]=1;
        for(int i=head[u];i;i=e[i].nxt)
        {
            v=e[i].to,tc=e[i].cst+h[u]-h[v];
            if(e[i].cap&&dis[v]>dis[u]+tc)
            {
                dis[v]=dis[u]+tc;
                p[v]=mkp(u,i);
                if(!vis[v]) q.push((node){dis[v],v});
            }
        }
    }
    return dis[t]!=inf;
}
signed main()
{
    n=read(),m=read(),s=n+1,t=n+2;
    int u,v,f,c,sumi=0,sumo=0;
    R(i,1,m)
    {
        u=read(),v=read(),c=read(),f=read();
        if(c>=f) 
        {
            link(u,v,c-f,1);
            link(v,u,f,1);
            link(u,v,inf,2);
        }
        else
        {
            ans+=(f-c);
            link(v,u,f-c,0);
            link(v,u,c,1);
            link(u,v,inf,2);
        }
        ind[v]+=f,oud[u]+=f;
    }
    R(i,2,n-1) 
    {
        if(ind[i]<oud[i]) link(i,t,oud[i]-ind[i],0),sumo+=oud[i]-ind[i];
        else link(s,i,ind[i]-oud[i],0),sumi+=ind[i]-oud[i];
    }
    link(s,1,inf-sumi,0),link(n,t,inf-sumo,0),link(1,n,inf,0);
    spfa();
    int minF;
    while(dij())
    {
        minF=inf;
        R(i,1,t) h[i]+=dis[i];
        for(int i=t;i^s;i=p[i].fi) ckmin(minF,e[p[i].se].cap);
        for(int i=t;i^s;i=p[i].fi) e[p[i].se].cap-=minF,e[p[i].se^1].cap+=minF;
        ans+=minF*h[t];
    }
    writeln(ans);
}
```





## [AGC038E] Gachapon

### solution

设$F(x)$为取了$n$个数以后还没有结束的EGF。则
$$
F(x)=e^x-\prod_{i=1}^n \left(e^{a_{i}x}-\sum_{j=0}^{B_i-1} \frac{(a_i)^j x^j}{j!} \right)
$$
其中$a_i$表示每次选中第$i$个数的概率，即$\frac{a_i}{\sum a_i}$。

稍微具体：

令$g_i$表示选了$i$个数停止的概率，$G(x)$表示$g_i$的指数生成函数，则有：
$$
\begin{align} G(x) & = \prod_{i=1}^n \left(\sum_{j= B_i}^\infty \frac{(a_i)^j x^j}{j!} \right) \\ & = \prod_{i=1}^n\left(\sum_{j=1}^{\infty} \frac{(a_i)^j x^j}{j!} -\sum_{j=1}^{B_i-1} \frac{(a_i)^j x^j}{j!} \right) \\ & = \prod_{i=1}^n \left(e^{a_i x}-\sum_{j=1}^{B_i-1} \frac{(a_i)^j x^j}{j!} \right) \\ \end{align}
$$
因此假设$f_i$表示选了$i$个数仍然没有停止的概率。

考虑求出$f_i$，因为直接对于所有长度为$i$的未停止序列计算概率之和并不好算，所以考虑用$1$减去已停止序列的概率之和。

令$F(x)$表示$f_i$的指数生成函数。
$$
\begin{align} F(x) & = \sum_{i=1}^{\infty} \frac{x^j}{j!} -G(x) \\ & = e^x -\prod_{i=1}^n \left(e^{a_i x}-\sum_{j=0}^{B_i-1}\frac{(a_j)^j x^j}{j!} \right) \\ \end{align}
$$
答案就是求$\sum f_i=\sum [\frac{x^i}{i!}]F(x)$





然后可以在$O\left(n\cdot \sum A\cdot \sum B+\sum A\cdot \left(\sum B \right)^2 \right)$的时间复杂度将$F$转成$F(x)=\sum\limits_{i} e^{p_i x}\cdot Q_i$。其中$p_i<1,Q_i$是一个系数不超过$B_i$的多项式。

然后对于每一个$i$要去枚举$Q$的某一个系数，于是就相当于要求：

{% raw %}
$$
\begin{align} \sum_{i=0}^{\infty} [\frac{x^i}{(i+b)!}]e^{px} & = b!\sum_{i=0}^{\infty} \binom {i+b} {i} p^i \\ & = \frac{b!}{(1-p)^{b+1}} \\ \end{align}
$$
{% endraw %}

右边等号的具体证明为：
$$
\begin{align} F_b & =\sum_{i=0}^{\infty} \binom {i+b}{i} p^i \\ & = \sum_{i=0}^{\infty}\binom{i+b-1}{i-1}p^i +\binom{i+b-1}{i}p^i \\ & = pF_b+F_{b-1} \\ \end{align}
$$

{% raw %}
$F_0=\frac{1}{1-p},(1-p)F_b=F_{b-1},F_b=\frac{1}{(1-p)^{b+1}}$
{% endraw %}




以及对于前面一些式子可能更详细的说明：

考虑将$F(x)$暴力展开，那么每一项都是$\sum_j Q_i(x) e^{\frac{i}{\sum a_i}x} x^j $，其中$Q_i(x)$可以直接暴力卷积或者分治FFT算出。

令$p=\frac{i}{\sum a_i}$然后考虑求出$e^{px}x^j$的贡献，令贡献为$F_{i,j}$，将原式展开

{% raw %}
$$
e^{px}x^j=\sum_{i=0}^{\infty} \frac{p^i x^{i+j}}{i!}=\sum_{i=0}^{\infty} \frac{p^i}{i!}x^{i+j}
$$
{% endraw %}

而$f_{i,j}=[x^{i+j}]F(x)\cdot (i+j)!$

所以

{% raw %}
$$
F_{i,j}=\sum _{i=0}^{\infty} p^i (i+j)^{\underline{j}}=j!\sum_{i=0}^{\infty}p^i\binom{i+j}{i}
$$
{% endraw %}

然后就又是上面的东西了。

枚举$i,j$计算$QF$即可。

```c++
int n,A[444],B[444],a[444];
int sumA,sumB;
int InvsumA;
int inv[1111],Finv[1111],fac[1111];
int dp[444][444][444];

inline void init()
{
    fac[0]=Finv[0]=inv[1]=1;
    R(i,2,1000) inv[i]=(mod-mod/i)*inv[mod%i]%mod;
    R(i,1,1000) fac[i]=i*fac[i-1]%mod,Finv[i]=Finv[i-1]*inv[i]%mod;
}
inline void add(int &x,int y){x+=y;x>=mod?x-=mod:1;}
inline void red(int &x,int y){x-=y;x<0?x+=mod:1;}
signed main()
{
    init();
    n=read();
    R(i,1,n) A[i]=read(),B[i]=read(),sumA+=A[i],sumB+=B[i];
    InvsumA=fpow(sumA);
    R(i,1,n) a[i]=1ll*A[i]*InvsumA%mod;
    dp[0][0][0]=1;
    R(i,0,n-1)
    {
        R(j,0,sumA)
        {
            R(k,0,sumB) add(dp[i+1][j][k],dp[i][j][k]);
            R(k,0,sumB) if(dp[i][j][k])
            {
                int pw=1;
                R(h,0,B[i+1]-1) 
                {
                    red(dp[i+1][j+A[i+1]][k+h],Finv[h]*dp[i][j][k]%mod*pw%mod);
                    pw=1ll*pw*a[i+1]%mod;
                }
            }
        }
    }
    int ans=0;
    R(i,1,sumA)
    {
        int p=1ll*(sumA-i)*InvsumA%mod;
        R(j,0,sumB) if(dp[n][i][j])
        {
            red(ans,dp[n][i][j]*fpow(1-p,mod-2-j)%mod*fac[j]%mod);
        }
    }
    writeln((ans%mod+mod)%mod);
}
```



## 「长乐集训 2017 Day10」生成树求和 加强版

### solution

考虑每一位是独立的，于是分开来考虑。

于是问题就变成了，有一个边权是$0,1,2$的图，对于每一个$x$，求出边权和为模$3$余$x$的生成树个数。

考虑给每种边权赋一个权值，然后跑矩阵树求所有生成树的权值之积的和，分别代入$1,1,1$、$1,\omega,\omega^2$和$1,\omega^2,\omega$，其中$\omega$指三次单位根。然后解一个方程就可以了。

具体：

假如边权和模$3$余$0$的个数为$a_0$，边权和模$3$余$1$的个数为$a_1$，边权和模$3$余$2$的个数为$a_2$。

假如对这三组都跑一遍矩阵树得到的解分别为$x_1,x_2,x_3$。
$$
\begin{cases} a_0+a_1+a_2=x_1 \\ a_0+\omega a_1+\omega^2 a_2=x_2 \\ a_0+\omega^2 a_1+\omega a_2=x_3 \end{cases}
$$
然后再解出$a_0,a_1,a_2$就行了。

