    string s;
    for(int _=read();_;_--)
    {
        cin>>s;tmp.pb(s);
    }
    writeln(tet.decrypt(tmp));
}
*/
```



## Topcoder-11779 Pikachu

https://vjudge.net/problem/TopCoder-11779

### 题意

给你$n$个单词，每个单词都有一定的出现频率，给每个单词编一个码满足没有一个单词编码是另一个单词的前缀，你只有三个字母$a,b,c$，其中$a,b$的代价为$2$，$c$的代价为$3$。

求最小代价，并且要求出方案数。

$n\leq 30$

### Solution

考虑按照深度从小到大考虑，一个显然的最优方法是按照出现频率从高到低放。于是考虑对于所有单词按照出现频率从大到小排序。然后考虑$dp[i][j][k][h][p]$表示当前考虑到了深度为$i,i+1,i+2$的点，当前已经放了第$j$个单词，深度为$i$的点有$k$个，深度为$i+1$的点有$h$，深度为$i+2$的点有$p$个的最小代价和达成最小代价的方案数。转移即是枚举当前选了多少个深度为$i$的点，假设选了$x$个，那么剩下的点会向下一层扩展，即深度为$i+2$的点会增加$2\times (k-x)$个，深度为$i+3$的点会增加$k-x$个。方案数大概要乘上$\binom {k}{x} \times x!$的系数。

考虑计算方案数的时候可以假设频率相同的单词不一样，然后对于每一段深度相同且频率相同的单词，假设其个数为$x$，那么之后把$x!$除回去即可。

```c++

ll f[33][33][33][33],dp[33][33][33][33];
ll a[33];
ll F[333],Finv[333],inv[333];
int n;
ll L[333],R[333];
ll suf[333];
inline void add(ll &x,ll y){x+=y;x>=mod?x-=mod:1;}
inline void init()
{
    memset(f,-1,sizeof(f));
    F[0]=Finv[0]=inv[1]=1;
    R(i,2,310) inv[i]=(mod-mod/i)*inv[mod%i]%mod;
    R(i,1,310) F[i]=1ll*i*F[i-1]%mod,Finv[i]=1ll*Finv[i-1]*inv[i]%mod;
}
inline ll C(ll n,ll m) 
{
    if(n<0||m<0||n<m) return 0;
    return 1ll*F[n]*Finv[n-m]%mod*Finv[m]%mod;
}
inline ll calc(ll x,ll l)
{
    if(!l) return 1;
    int ps=x+l;
    return 1ll*F[l]*C(min(L[ps],ps-R[ps]+L[ps]-x),min(l,R[ps]))%mod;
}
pii dfs(ll t,ll k,ll h,ll p)
{
    if(t+k>=n) return mkp(0,C(k,n-t)*F[n-t]%mod);
    if(!k&&!h&&!p) return mkp(inf,0);
    if(~f[t][k][h][p]) return mkp(f[t][k][h][p],dp[t][k][h][p]);
    ll mn=inf,cnt=0;
    R(i,0,k) 
    {
        static ll kk,hh,pp,T,t1,t2;
        static pii tt;
        T=t+i,kk=h,hh=p+2*(k-i),pp=k-i;
        tt=dfs(T,kk,hh,pp);
        t1=tt.fi,t2=tt.se%mod;
        t1+=suf[t+i+1];t2=1ll*t2*calc(t,i)%mod*C(k,i)%mod;
        if(mn>t1) mn=t1,cnt=t2;
        else if(mn==t1) add(cnt,t2);
    }
    f[t][k][h][p]=mn,dp[t][k][h][p]=cnt;
    return mkp(f[t][k][h][p],dp[t][k][h][p]);
}
struct Pikachu
{
    vector<int> bestEncoding(vector<int>freq)
    {
        n=freq.size();R(i,1,n) a[i]=freq[i-1];
        init();
        sort(a+1,a+n+1);reverse(a+1,a+n+1);
        L(i,1,n) suf[i]=suf[i+1]+a[i];
        R(i,1,n) R[i]=a[i]==a[i-1]?R[i-1]+1:1;
        L(i,1,n) L[i]=R[i]+1==R[i+1]?L[i+1]:R[i];
        pii t=dfs(0,1,0,0);
        vector<int>tt;tt.pb(t.fi);tt.pb(t.se);
        return tt;
    }   
};
