signed main()
{
    ll x;
    vector<int>tmp,t;
    for(int _=read();_;_--) x=read(),tmp.pb(x);
    t=tt.bestEncoding(tmp);
    printf("%lld %lld\n",t[0],t[1]);
}
*/
/*
