### sol：

考虑$dp_{i,j,k}$表示$i$这个子树，切了$j$段，当前连通块大小为$k$的最小和。

容易发现，这个状态过多，所以不行。将$(k,dp_{i,j,k})$记作二元组，考虑要保留哪些二元组。

容易发现，每个连通块，一个子树合并进去，相当于$(x,y)$和另一个点对$(u,v)$合并，权值和为$(x+u)^2+y+v$，也就是$x^2+2xu+u^2+y+v$。这其实是一个斜率优化的形式。当$u,v$为定值的时候，相当于$(x^2+y,x)$点（？乘上$(1,2u)$的最小值，这个东西的最小值一定在下凸壳上，所以只需要保留$(x^2+y,x)$（？下凸壳上的递减段部分即可。对每个$(i,j)$保留它在下凸壳上的一个状态即可$k_1^2+dp_{i,j,k_1}$。

```c++
int n;
int a[333],fa[333],siz[333];
vector<int>g[333];
vector<pii>e[333][333],t[2][333],tmp[333];
//e:(k,dp[i][j][k]),tuke
int cur,sizu;
inline int calc(pii x) {return x.fi*x.fi+x.se;}
inline pii add_pair(pii x,pii y) {return mkp(x.fi+y.fi,x.se+y.se);}
void dfs(int u)
{
	siz[u]=1;
	for(int v:g[u]) if(v!=fa[u])
	{
		fa[v]=u;
		dfs(v);
		siz[u]+=siz[v];
	}
	R(i,0,siz[u]+2) t[0][i].clear(); 
	cur=0,sizu=1;
	t[0][0].pb(mkp(a[u],0));
	for(int v:g[u]) if(v!=fa[u])
	{
		cur^=1;
		R(j,0,sizu+siz[v]-1) t[cur][j].clear(),tmp[j].clear();
		R(j,0,sizu-1) 
		{
			R(k,0,siz[v]) 
			{
				for(pii k1:t[cur^1][j])//mer
				{
					int mn=inf;
					for(pii k2:e[v][k]) if(ckmin(mn,calc(add_pair(k1,k2)))) tmp[j+k].pb(add_pair(k1,k2));
				}
			}
		} 
		sizu+=siz[v];
		R(j,0,sizu-1) 
		{
			sort(tmp[j].begin(),tmp[j].end());
			int mn=inf;
			for(pii k1:tmp[j]) if(ckmin(mn,calc(k1))) t[cur][j].pb(k1);
		}
	}
	R(i,0,sizu) e[u][i].clear();
	R(i,0,sizu-1) 
	{
		pii tt=*(t[cur][i].end()-1);
		e[u][i+1].pb(mkp(0,calc(tt)));//cut
		for(pii k1:t[cur][i]) e[u][i].pb(k1);
	}
}
signed main()
{
