		int u,v;
		R(i,2,n) u=read(),v=read(),g[u].pb(v),g[v].pb(u);
		dfs(1);
		R(i,1,n) 
		{
			pii tt=*(e[1][i].begin());
			printf("%lld ",tt.se);
		} 
