		R(i,0,n-1) s3[i]=(s3[i]+s1[i])%mod;
		NTT(s3,0,n);
		R(i,nd2,n-1) G[i+l]=(G[i+l]+s3[i])%mod;
	}
	cdq(mid,r);
}
signed main()
{
	m=read();scanf("%s",s+1);
	init_FAC(m+10);
	G[1]=1;
	R(i,1,m) if(s[i]=='1') F[i]=Finv[i-1];
	for(n=1;n<=m;n<<=1);
	cdq(0,n);
	R(i,1,m) writeln(1ll*fac[i]*G[i]%mod);
}
