		sort(a,a+k),sort(b,b+k);
		int ans=n;
		R(x,0,k-1)
		{
			vector<int>c={0,n};
			R(i,0,k-1) c.pb((a[i]-b[(i+x)%k]+n)%n);
			sort(c.begin(),c.end());
			R(i,0,k) ckmin(ans,n-(c[i+1]-c[i])+min(c[i],n-c[i+1]));
