		do
		{
			bel[u]=totscc;
			instk[u=stk[top--]]=0;
		}while(low[u]!=dfn[u]);
		*/

		while(stk[top+1]!=u)
		{
			bel[stk[top]]=totscc;
			instk[stk[top--]]=0;
		}

	}
}
signed main()
{
	n=read(),m=read();
	int u,v,a,b;
	R(i,1,m)
	{
		u=read(),a=read(),v=read(),b=read();
