如果形成了一个环，那么可以缩成一个点，这个点的权值就是这个连通分量的答案。然后相当于找树上路径最大值，考虑`lct`维护。

当我们连成一个环时，我们保留一个代表点，维护一个并查集，使原来路径上所有点指向这个点，把他们的权值都给这个点，然后把整棵`splay`的边弄断。然后每次找一个点父亲时，要在并查集上`getfa`一下，顺便把这个点的父亲指向`getfa`得到的点。

以及实际题好像是操作2是增加b...

```c++
#include <iostream>
#include <cmath>
#include <cstdio>

const int maxn=150007;

using namespace std;

int n,m,x,y,op;
int p[maxn],acc[maxn];

struct node{
    int l,r,fa;
    int data,sum;
    int rev;
}t[maxn];

int getfa(int x)
{
    if (!p[x]) return x;
    return (p[x]=getfa(p[x]));
}

void union1(int x,int y)
{
    int u=getfa(x),v=getfa(y);
    if (u==v) return;
    p[v]=u;
}

void updata(int x)
{
    t[x].sum=t[x].data+t[t[x].l].sum+t[t[x].r].sum;
}

bool isroot(int x)
{
    t[x].fa=getfa(t[x].fa);
    return ((t[t[x].fa].l!=x) && (t[t[x].fa].r!=x));
}

void rttr(int x)
{
    int y=t[x].l;
    t[x].l=t[y].r;
    if (t[y].r) t[t[y].r].fa=x;
    t[x].fa=getfa(t[x].fa);
    if (x==t[t[x].fa].l) t[t[x].fa].l=y;
    else if (x==t[t[x].fa].r) t[t[x].fa].r=y;
    t[y].fa=getfa(t[y].fa);
    t[y].fa=t[x].fa;
    t[x].fa=y;
    t[y].r=x;
    updata(x); updata(y);
}

void rttl(int x)
{
    int y=t[x].r;
    t[x].r=t[y].l;
    if (t[y].l) t[t[y].l].fa=x;
    t[x].fa=getfa(t[x].fa);
    if (x==t[t[x].fa].l) t[t[x].fa].l=y;
    else if (x==t[t[x].fa].r) t[t[x].fa].r=y;
    t[y].fa=getfa(t[y].fa);
    t[y].fa=t[x].fa;
    t[x].fa=y;
    t[y].l=x;
    updata(x); updata(y);
}

void remove(int x)
{
    if (!isroot(x)) remove(t[x].fa=getfa(t[x].fa));
    if (t[x].rev)
    {
        t[x].rev^=1;
        swap(t[x].l,t[x].r);
        if (t[x].l) t[t[x].l].rev^=1;
        if (t[x].r) t[t[x].r].rev^=1;
    }
}

void splay(int x)
{
    remove(x);
    while (!isroot(x))
    {
        int p=t[x].fa=getfa(t[x].fa),g=t[p].fa=getfa(t[p].fa);
        if (isroot(p))
        {
            if (x==t[p].l) rttr(p);
                      else rttl(p);
        }
        else
        {
            if (x==t[p].l)
            {
                if (p==t[g].l) rttr(p),rttr(g);
                          else rttr(p),rttl(g);
            }
            else
            {
                if (p==t[g].l) rttl(p),rttr(g);
                          else rttl(p),rttl(g);
            }
        }
    }
}

void access(int x)
{
    int y=0;
    while (x)
    {
        splay(x);
        t[x].r=y;
        updata(x);
        y=x,x=t[x].fa=getfa(t[x].fa);
    }
}

void makeroot(int x)
{
    access(x);
    splay(x);
    t[x].rev^=1;
}

void link(int x,int y)
{
    makeroot(x);
    access(y);
    splay(y);
    t[x].fa=y;
}

void solve(int x,int root)
{
    if (x!=root) t[root].data+=t[x].data;
    union1(root,x);
    if (t[x].l) solve(t[x].l,root);
    if (t[x].r) solve(t[x].r,root);
    t[x].l=0;
    t[x].r=0;
}

int find(int x)
{
    if (!acc[x]) return x;
    return (acc[x]=find(acc[x]));
}

void union2(int x,int y)
{
    int u=find(x),v=find(y);
    if (u==v) return;
    acc[u]=v;
}

int main()
{
    freopen("graph.in","r",stdin);
    freopen("graph.out","w",stdout);
    scanf("%d%d",&n,&m);
    for (int i=1;i<=n;i++)
    {
        scanf("%d",&t[i].data);
        t[i].sum=t[i].data;
    }           
    for (int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&op,&x,&y);  
        if (op==1)
        {
            x=getfa(x); y=getfa(y);         
            if (find(x)!=find(y))
            {
                link(x,y);
                union2(x,y);
            }
            else
            {
                makeroot(x);
                access(y);
                splay(y);
                solve(y,y);
            }
        }
        if (op==2)
        {
            x=getfa(x);
            t[x].data+=y;
            t[x].sum+=y;            
        }
        if (op==3)
        {
            x=getfa(x); y=getfa(y); 
            if (find(x)!=find(y)) printf("-1\n");
            else
            {               
                makeroot(x);
                access(y);
                splay(y);
                printf("%d\n",t[y].sum);
            }
        }
    }
}
