    R(i,1,n) x=read(),y=read(),a[i]=node(x,y);
    R(i,1,m) x=read(),y=read(),b[i]=node(-x,-y);
    solve(n,a);solve(m,b);
    minkow(a,b,c,n,m,nm);
    solve(nm,c);
    node lwp=c[1];
    R(i,1,nm) c[i]=c[i]-lwp;
    while(q--)
    {
        x=read(),y=read();
        writeln(check(node(x,y)-lwp,c,nm));
    }

}
